    PENDING_USERS_PATH = os.path.join(DATA_DIR, "pending_users.json")

    def _load_pending_users():
        """Load pending access requests."""
        if not os.path.isfile(PENDING_USERS_PATH):
            return []
        with open(PENDING_USERS_PATH) as f:
            return json.load(f)

    def _save_pending_users(data):
        """Save pending access requests."""
        os.makedirs(os.path.dirname(PENDING_USERS_PATH), exist_ok=True)
        with open(PENDING_USERS_PATH, "w") as f:
            json.dump(data, f, indent=2)

    def load_customers():
        """Load customers from JSON."""
        if not os.path.isfile(CUSTOMERS_PATH):
            os.makedirs(os.path.dirname(CUSTOMERS_PATH), exist_ok=True)
            with open(CUSTOMERS_PATH, "w") as f:
                json.dump([], f)
            return []
        with open(CUSTOMERS_PATH, "r") as f:
            return json.load(f)

    def save_customers(data):
        """Save customers to JSON."""
        os.makedirs(os.path.dirname(CUSTOMERS_PATH), exist_ok=True)
        with open(CUSTOMERS_PATH, "w") as f:
            json.dump(data, f, indent=2)

    def load_quote_data(job_code):
        """Load quote data for a project."""
        safe = re.sub(r'[^A-Za-z0-9_-]', '_', job_code)
        qpath = os.path.join(QUOTES_DIR, f"{safe}.json")
        if os.path.isfile(qpath):
            with open(qpath) as f:
                return json.load(f)
        return None

    def save_quote_data(job_code, data):
        """Save quote data for a project."""
        os.makedirs(QUOTES_DIR, exist_ok=True)
        safe = re.sub(r'[^A-Za-z0-9_-]', '_', job_code)
        qpath = os.path.join(QUOTES_DIR, f"{safe}.json")
        data["updated_at"] = datetime.datetime.now().isoformat()
        with open(qpath, "w") as f:
            json.dump(data, f, indent=2)

