# SECURITY HARDENING CONSTANTS & HELPERS
# ─────────────────────────────────────────────

COOKIE_MAX_AGE_HOURS = 8  # Session cookie expiry
ALLOWED_ORIGINS = os.environ.get("TITANFORGE_ALLOWED_ORIGINS", "").split(",")
# Remove empty strings from the list
ALLOWED_ORIGINS = [o.strip() for o in ALLOWED_ORIGINS if o.strip()]

# Login rate limiting: track failed attempts per IP
_login_attempts = {}  # { ip: [ timestamp, timestamp, ... ] }
_LOGIN_MAX_ATTEMPTS = 5
_LOGIN_WINDOW_SECONDS = 15 * 60  # 15 minutes


def _cleanup_login_attempts():
    """Remove expired entries from the login attempts tracker."""
    cutoff = time.time() - _LOGIN_WINDOW_SECONDS
    expired_ips = [ip for ip, attempts in _login_attempts.items()
                   if not attempts or attempts[-1] < cutoff]
    for ip in expired_ips:
        del _login_attempts[ip]


def validate_password(password):
    """Validate password complexity requirements.
    Returns (ok: bool, error_message: str or None).
    """
    if len(password) < 8:
        return False, "Password must be at least 8 characters long."
    if not re.search(r'[A-Z]', password):
        return False, "Password must contain at least one uppercase letter."
    if not re.search(r'[0-9]', password):
        return False, "Password must contain at least one number."
    return True, None


# ─────────────────────────────────────────────
# BASE AUTHENTICATED HANDLER WITH ROLE CHECKING
# ─────────────────────────────────────────────

class BaseHandler(tornado.web.RequestHandler):
    """Base handler that checks authentication and role permissions."""
    required_roles = None  # Override in subclasses. None = no role check.

    def set_default_headers(self):
        """Set security-related default headers including CORS and security hardening."""
        origin = self.request.headers.get("Origin", "")
        if ALLOWED_ORIGINS and origin in ALLOWED_ORIGINS:
            self.set_header("Access-Control-Allow-Origin", origin)
        elif not ALLOWED_ORIGINS:
            # If no origins configured, allow same-origin only (no header set)
            pass
        self.set_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.set_header("Access-Control-Allow-Headers", "Content-Type, X-XSRFToken")
        # SEC-011: Apply security headers (CSP, X-Frame-Options, etc.)
        if HAS_SECURITY:
            apply_security_headers(self)
        else:
            self.set_header("X-Frame-Options", "SAMEORIGIN")
            self.set_header("X-Content-Type-Options", "nosniff")
            self.set_header("Referrer-Policy", "strict-origin-when-cross-origin")
            self.set_header("Content-Security-Policy",
                            "default-src 'self'; script-src 'self' 'unsafe-inline' https://cdnjs.cloudflare.com; "
                            "style-src 'self' 'unsafe-inline'; img-src 'self' data: blob:; "
                            "font-src 'self' data:; connect-src 'self'; frame-ancestors 'self';")

    def check_xsrf_cookie(self):
        """SEC-001: CSRF check override — log-only for now until forms send XSRF tokens.
        TODO: Remove this override once all forms/AJAX include the _xsrf token,
        then enable xsrf_cookies=True in the Application constructor."""
        pass

    def options(self, *args, **kwargs):
        """Handle CORS preflight requests."""
        self.set_status(204)
        self.finish()

    def write_json(self, data):
        """Helper to write JSON response with correct Content-Type."""
        self.set_header("Content-Type", "application/json")
        self.write(json_encode(data))

    def get_current_user(self):
        """Get current authenticated user (username or 'admin' in dev mode)."""
        cookie = self.get_secure_cookie("sa_user")
        if cookie:
            return cookie.decode("utf-8")
        if not AUTH_ENABLED:
            return "admin"
        return None

    def get_user_role(self):
        """Get current user's primary role."""
        if not AUTH_ENABLED:
            return "admin"
        current = self.get_current_user()
        if not current:
            return None
        users = load_users()
        return users.get(current, {}).get("role", "viewer")

    def get_user_roles(self):
        """Get all roles for the current user as a list.

        Supports the multi-role RBAC system. Falls back to wrapping
        the single legacy role in a list.
        """
        if not AUTH_ENABLED:
            return ["admin"]
        current = self.get_current_user()
        if not current:
            return ["viewer"]
        users = load_users()
        udata = users.get(current, {})
        roles = udata.get("roles")
        if roles and isinstance(roles, list):
            return roles
        # Fallback: wrap single role
        single = udata.get("role", "viewer")
        return [single] if single else ["viewer"]

    def check_permission(self, permission: str) -> bool:
        """Check if current user has a specific permission."""
        roles = self.get_user_roles()
        if not roles:
            return False
        if HAS_RBAC:
            perm_set = merge_permissions(roles)
            return perm_set.can(permission)
        return permission in get_user_permissions(roles[0])

    def get_permission_set(self) -> 'PermissionSet':
        """Get the full PermissionSet for the current user."""
        roles = self.get_user_roles()
        if HAS_RBAC and roles:
            return merge_permissions(roles)
        # Fallback: create a minimal PermissionSet
        ps = PermissionSet() if HAS_RBAC else None
        return ps

    def prepare(self):
        """Check auth before handling request."""
        if not AUTH_ENABLED:
            # Auto-login as admin when auth is disabled (testing mode)
            if not self.get_secure_cookie("sa_user"):
                _cookie_kw = SECURE_COOKIE_KWARGS if HAS_SECURITY else {"httponly": True, "samesite": "Lax"}
                self.set_secure_cookie("sa_user", "admin", expires_days=1, **_cookie_kw)
            return
        path = self.request.path
        if path.startswith("/auth/") or path.startswith("/static/"):
            return

        current = self.get_current_user()
        if not current:
            if self.request.method == "GET":
                self.redirect("/auth/login")
            else:
                self.set_status(401)
                self.write(json_encode({"error": "Not authenticated"}))
            raise tornado.web.Finish()

        # Check role permissions if required
        if self.required_roles is not None:
            role = self.get_user_role()
            if not check_role(role, self.required_roles):
                # For page requests, redirect to dashboard with message
                if self.request.method == "GET" and not self.request.path.startswith("/api/"):
                    self.redirect("/?msg=insufficient_permissions")
                    raise tornado.web.Finish()
                self.set_status(403)
                self.write(json_encode({"error": "Insufficient permissions for this action"}))
                raise tornado.web.Finish()

    def write_error(self, status_code, **kwargs):
        """Unified error handler — returns JSON for API routes, styled HTML for pages."""
        # Log the error with traceback if available
        if "exc_info" in kwargs:
            logger.error("Unhandled %d on %s %s",
                         status_code, self.request.method, self.request.uri,
                         exc_info=kwargs["exc_info"])

        is_api = self.request.path.startswith("/api/")
        reason = self._reason if hasattr(self, '_reason') else "Internal Server Error"

        if is_api:
            self.set_header("Content-Type", "application/json")
            self.finish(json_encode({
                "ok": False,
                "error": reason,
                "status": status_code,
            }))
        else:
            self.set_header("Content-Type", "text/html")
            self.finish(
                f"<!DOCTYPE html><html><head><title>Error {status_code}</title>"
                f"<style>body{{font-family:-apple-system,BlinkMacSystemFont,sans-serif;"
                f"background:#0F172A;color:#E2E8F0;display:flex;align-items:center;"
                f"justify-content:center;height:100vh;margin:0;}}"
                f".card{{background:#1E293B;border:1px solid #334155;border-radius:16px;"
                f"padding:48px;text-align:center;max-width:480px;}}"
                f"h1{{color:#F87171;font-size:3rem;margin:0 0 8px;}} "
                f"h2{{color:#FFF;margin:0 0 12px;}} "
                f"p{{color:#94A3B8;line-height:1.6;}} "
                f"a{{color:#60A5FA;text-decoration:none;font-weight:600;}}</style></head>"
                f"<body><div class='card'><h1>{status_code}</h1>"
                f"<h2>{reason}</h2>"
                f"<p>Something went wrong. If this keeps happening, contact your admin.</p>"
                f"<br><a href='/'>← Back to Dashboard</a></div></body></html>"
            )

    def _log(self, action, entity_type="", entity_id="", details=None, user_override=None):
        """Log an activity for the current user and award XP. Safe to call even if db not available."""
        try:
            if USE_SQLITE:
                import db as _db
                username = user_override or self.get_current_user() or "anonymous"
                _db.log_activity(
                    user=username,
                    action=action,
                    entity_type=entity_type,
                    entity_id=str(entity_id) if entity_id else "",
                    details=details,
                    ip_address=self.request.remote_ip or "",
                )
                # Award XP for the action (gamification)
                try:
                    _db.award_xp(username, action, entity_type, str(entity_id) if entity_id else "")
                except Exception:
                    logger.debug("XP award failed", exc_info=True)
        except Exception:
            logger.debug("Activity log write failed", exc_info=True)

    def render_with_nav(self, html: str, active_page: str = "",
                        job_code: str = "", breadcrumbs=None):
        """Render HTML with the unified sidebar navigation injected.

        Args:
            html: Raw HTML string from template
            active_page: Which sidebar item to highlight
            job_code: If set, shows project sub-nav in sidebar
            breadcrumbs: Optional list of (label, url) tuples for breadcrumb bar.
                         The last item is rendered as plain text (current page).
        """
        from templates.shared_nav import inject_nav

        # Build breadcrumb HTML if provided
        bc_html = ""
        if breadcrumbs:
            parts = []
            for i, (label, url) in enumerate(breadcrumbs):
                if i == len(breadcrumbs) - 1:
                    parts.append(f'<span style="color:#e2e8f0;">{label}</span>')
                else:
                    parts.append(f'<a href="{url}" style="color:#3b82f6;text-decoration:none;">{label}</a>')
            bc_html = ('<div style="padding:12px 32px 0;font-size:13px;color:#94a3b8;'
                       "font-family:'Inter','Segoe UI',sans-serif;\">")
            bc_html += '<span style="margin:0 8px;color:#475569;">\u203a</span>'.join(parts)
            bc_html += '</div>'

        user = self.get_current_user() or "local"
        role = self.get_user_role() or "admin"
        roles = self.get_user_roles()
        users = load_users()
        display = users.get(user, {}).get("display_name", user) if user != "local" else "Admin"

        # Pass the actual request path so the sidebar can do exact URL matching
        request_path = getattr(self.request, 'uri', '') or getattr(self.request, 'path', '') or ''
        result = inject_nav(html, active_page=active_page, job_code=job_code,
                            user_name=display, user_role=role, user_roles=roles,
                            request_path=request_path)

        # Inject breadcrumb inside .tf-main, right after the contextbar
        if bc_html:
            marker = 'tf-contextbar-actions"></div></div>'
            result = result.replace(marker, marker + '\n' + bc_html, 1)
        self.set_header("Content-Type", "text/html; charset=utf-8")
        self.write(result)


