class DashboardStatsAPIHandler(BaseHandler):
    """GET /api/dashboard/stats — Aggregated stats for the dashboard."""
    def get(self):
        try:
            user = self.get_current_user() or "local"
            users_db = load_users()
            role = users_db.get(user, {}).get("role", "viewer") if user != "local" else "admin"

            result = {"ok": True}

            # ── Active projects & stage counts ──
            active_projects = 0
            stage_counts = {}
            in_engineering = 0
            in_fabrication = 0
            ready_to_ship = 0
            try:
                os.makedirs(PROJECTS_DIR, exist_ok=True)
                for d in os.listdir(PROJECTS_DIR):
                    dpath = os.path.join(PROJECTS_DIR, d)
                    meta_path = os.path.join(dpath, "metadata.json")
                    if os.path.isdir(dpath) and os.path.isfile(meta_path):
                        try:
                            with open(meta_path) as f:
                                meta = json.load(f)
                            if meta.get("archived", False):
                                continue
                            stage = meta.get("stage", "quote")
                            if stage != "complete":
                                active_projects += 1
                            stage_counts[stage] = stage_counts.get(stage, 0) + 1
                            if stage in ("engineering", "shop_drawings", "shop-drawings"):
                                in_engineering += 1
                            elif stage == "fabrication":
                                in_fabrication += 1
                            elif stage in ("shipping", "install"):
                                ready_to_ship += 1
                        except Exception:
                            pass
            except Exception:
                pass

            result["active_projects"] = active_projects
            result["stage_counts"] = stage_counts
            result["in_engineering"] = in_engineering
            result["in_fabrication"] = in_fabrication
            result["ready_to_ship"] = ready_to_ship

            # ── Open work orders ──
            open_work_orders = 0
            active_work_orders = []
            work_order_items = []
            try:
                from shop_drawings.work_orders import list_all_work_orders, load_all_active_items
                all_wos = list_all_work_orders(SHOP_DRAWINGS_DIR)
                for wo in all_wos:
                    status = wo.get("status", "")
                    if status not in ("complete", "completed", "cancelled"):
                        open_work_orders += 1
                        active_work_orders.append(wo)
                try:
                    items = load_all_active_items(SHOP_DRAWINGS_DIR)
                    for item in items:
                        if hasattr(item, 'to_dict'):
                            work_order_items.append(item.to_dict())
                        elif hasattr(item, '__dict__'):
                            work_order_items.append(item.__dict__)
                        else:
                            work_order_items.append(item)
                except Exception:
                    pass
            except Exception:
                pass

            result["open_work_orders"] = open_work_orders
            result["active_work_orders"] = active_work_orders[:10]
            result["work_order_items"] = work_order_items[:20]

            # ── WO Overhaul Metrics (NCR count, QC progress, traceability, critical items) ──
            wo_ncr_count = 0
            wo_qc_checklist_total = 0
            wo_qc_checklist_done = 0
            wo_traced_items = 0
            wo_total_fab_items = 0
            wo_critical_items = 0
            wo_critical_passed = 0
            wo_in_ncr_hold = 0
            try:
                from shop_drawings.work_orders import load_work_order
                for ws in (active_work_orders or []):
                    jc = ws.get("job_code", "")
                    wid = ws.get("work_order_id", "")
                    if not jc or not wid:
                        continue
                    wo_obj = load_work_order(SHOP_DRAWINGS_DIR, jc, wid)
                    if wo_obj is None:
                        continue
                    if wo_obj.status == "ncr_hold":
                        wo_in_ncr_hold += 1
                    for itm in wo_obj.items:
                        if getattr(itm, "item_category", "fabricated") != "fabricated":
                            continue
                        wo_total_fab_items += 1
                        # NCR count
                        ncr_id = getattr(itm, "ncr_id", "")
                        if ncr_id:
                            wo_ncr_count += 1
                        # QC checklist progress
                        cl = getattr(itm, "qc_checklist", [])
                        wo_qc_checklist_total += len(cl)
                        wo_qc_checklist_done += sum(1 for c in cl if c.get("result") in ("pass", "n/a"))
                        # Traceability
                        hn = getattr(itm, "heat_number", "")
                        if hn:
                            wo_traced_items += 1
                        # Critical items
                        if getattr(itm, "is_critical", False):
                            wo_critical_items += 1
                            if getattr(itm, "qc_final_status", "") == "passed":
                                wo_critical_passed += 1
            except Exception:
                pass

            result["wo_ncr_count"] = wo_ncr_count
            result["wo_in_ncr_hold"] = wo_in_ncr_hold
            result["wo_qc_checklist_progress"] = {
                "total": wo_qc_checklist_total,
                "done": wo_qc_checklist_done,
                "pct": round(wo_qc_checklist_done / wo_qc_checklist_total * 100, 1) if wo_qc_checklist_total > 0 else 0,
            }
            result["wo_traceability"] = {
                "traced": wo_traced_items,
                "total": wo_total_fab_items,
                "pct": round(wo_traced_items / wo_total_fab_items * 100, 1) if wo_total_fab_items > 0 else 0,
            }
            result["wo_critical_items"] = {
                "total": wo_critical_items,
                "passed": wo_critical_passed,
                "pct": round(wo_critical_passed / wo_critical_items * 100, 1) if wo_critical_items > 0 else 0,
            }

            # ── Pending QC items & NCRs ──
            pending_qc = 0
            qc_items = []
            open_ncrs = []
            recent_signoffs = []
            try:
                os.makedirs(QC_DIR, exist_ok=True)
                for fname in os.listdir(QC_DIR):
                    if fname.endswith(".json"):
                        fpath = os.path.join(QC_DIR, fname)
                        try:
                            with open(fpath) as f:
                                qc_data = json.load(f)
                            job_code = fname.replace(".json", "")
                            for insp in qc_data.get("inspections", []):
                                status = insp.get("status", "pending")
                                if status in ("pending", "in_progress"):
                                    pending_qc += 1
                                    insp["job_code"] = job_code
                                    qc_items.append(insp)
                                elif status in ("passed", "completed", "signed"):
                                    insp["job_code"] = job_code
                                    recent_signoffs.append(insp)
                            for ncr in qc_data.get("ncrs", []):
                                ncr_status = ncr.get("status", "open")
                                if ncr_status in ("open", "in_progress"):
                                    ncr["job_code"] = job_code
                                    open_ncrs.append(ncr)
                        except Exception:
                            pass
            except Exception:
                pass

            result["pending_qc"] = pending_qc
            result["qc_items"] = qc_items[:20]
            result["open_ncrs"] = open_ncrs[:10]
            result["recent_signoffs"] = recent_signoffs[-10:]

            # ── Inventory alerts ──
            inventory_alerts = 0
            try:
                inv = load_inventory()
                coils = inv.get("coils", inv) if isinstance(inv, dict) else {}
                if isinstance(coils, dict):
                    for cid, c in coils.items():
                        if isinstance(c, dict):
                            avail = (c.get("stock_lbs", 0) or 0) - (c.get("committed_lbs", 0) or 0)
                            min_stock = c.get("min_stock_lbs", 2000) or 2000
                            if avail <= 0 or avail < min_stock:
                                inventory_alerts += 1
            except Exception:
                pass

            result["inventory_alerts"] = inventory_alerts

            # ── Recent activity (admin, estimator, PM roles) ──
            recent_activity = []
            activity_roles = ["admin", "god_mode", "owner", "general_manager", "executive",
                              "estimator", "project_manager"]
            if role in activity_roles:
                try:
                    if USE_SQLITE:
                        import db as _db
                        entries = _db.get_activity_log(limit=10, offset=0)
                        recent_activity = entries if isinstance(entries, list) else []
                except Exception:
                    pass

            result["recent_activity"] = recent_activity

            # ── Users online estimate (admin) ──
            admin_roles = ["admin", "god_mode", "owner", "general_manager"]
            if role in admin_roles:
                result["users_online"] = max(1, len([u for u in users_db.values()
                                                       if isinstance(u, dict)
                                                       and u.get("last_login", "")]))

            self.set_header("Content-Type", "application/json")
            self.write(json_encode(result))

        except Exception as e:
            logger.error(f"DashboardStatsAPIHandler error: {e}", exc_info=True)
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


