class ProjectPageHandler(BaseHandler):
    """GET /project/{job_code} — Full project page."""
    def get(self, job_code):
        try:
            safe_name = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            meta_path = os.path.join(PROJECTS_DIR, safe_name, "metadata.json")

            if not os.path.isfile(meta_path):
                self.set_status(404)
                # SEC-009: Escape job_code to prevent reflected XSS
                self.write(f"<h2>Project '{html.escape(job_code)}' not found</h2><a href='/'>Back to Dashboard</a>")
                return

            with open(meta_path) as f:
                metadata = json.load(f)

            role = self.get_user_role() or "viewer"
            display = "User"
            if AUTH_ENABLED:
                user = self.get_current_user()
                users = load_users()
                display = users.get(user, {}).get("display_name", user or "User")

            html = PROJECT_PAGE_HTML
            html = html.replace("{{JOB_CODE}}", _html_escape(job_code))
            html = html.replace("{{METADATA_JSON}}", _safe_json_embed(metadata))
            html = html.replace("{{USER_ROLE}}", role)
            html = html.replace("{{USER_NAME}}", _html_escape(display))
            html = html.replace("{{STAGES_JSON}}", json.dumps(PROJECT_STAGES))
            html = html.replace("{{NEXT_STEPS_JSON}}", json.dumps(STAGE_NEXT_STEPS))
            html = html.replace("{{DOC_CATEGORIES_JSON}}", json.dumps(DEFAULT_DOC_CATEGORIES))

            proj_name = metadata.get("project_name", job_code)
            self.render_with_nav(html, active_page="project", job_code=job_code,
                                    breadcrumbs=[("Dashboard", "/"), ("Projects", "/projects"), (proj_name, "")])


        except Exception as e:
            logger.error(f"{self.__class__.__name__}.{self.request.method}() error: {e}", exc_info=True)
            self.set_status(500)
            self.write(f"<h2>Error</h2><p>{html.escape(str(e))}</p>")

class ProjectTimelineHandler(BaseHandler):
    """GET /api/project/timeline — Get project milestone timeline."""
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        job_code = self.get_argument("job_code", "")
        if not job_code:
            self.write(json_encode({"ok": False, "error": "Missing job_code"}))
            return

        try:
            safe_name = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            meta_path = os.path.join(PROJECTS_DIR, safe_name, "metadata.json")

            if not os.path.isfile(meta_path):
                self.write(json_encode({"ok": False, "error": "Project not found"}))
                return

            with open(meta_path) as f:
                project = json.load(f)

            milestones = []

            # 1. Project created
            milestones.append({
                "key": "project_created",
                "label": "Project Created",
                "date": project.get("created_at", ""),
                "complete": True,
                "icon": "\U0001f4cb"
            })

            # 2. SA Quote generated
            sa_quote = project.get("sa_quote_number", "")
            milestones.append({
                "key": "sa_quote",
                "label": "SA Quote Generated",
                "date": project.get("sa_quote_date", ""),
                "complete": bool(sa_quote),
                "icon": "\U0001f4ca"
            })

            # 3. TC Quote generated
            tc_dir = os.path.join(DATA_DIR, "tc_quotes")
            tc_path = os.path.join(tc_dir, f"{job_code}.json")
            tc_exists = os.path.exists(tc_path)
            tc_date = ""
            if tc_exists:
                try:
                    with open(tc_path) as f:
                        tc_data = json.load(f)
                    tc_date = tc_data.get("saved_at", "")
                except Exception:
                    pass
            milestones.append({
                "key": "tc_quote",
                "label": "TC Quote Generated",
                "date": tc_date,
                "complete": tc_exists,
                "icon": "\U0001f4b0"
            })

            # 4. Quote signed
            stage = project.get("stage", "")
            milestones.append({
                "key": "quote_signed",
                "label": "Quote Signed",
                "date": project.get("quote_signed_date", ""),
                "complete": stage in ["production", "fabrication", "shipping", "complete", "shop_drawings"],
                "icon": "\u270d\ufe0f"
            })

            # 5. Shop drawings
            sd_dir = os.path.join(SHOP_DRAWINGS_DIR, job_code, "pdfs")
            has_drawings = os.path.isdir(sd_dir) and len(os.listdir(sd_dir)) > 0
            milestones.append({
                "key": "shop_drawings",
                "label": "Shop Drawings Complete",
                "date": "",
                "complete": has_drawings,
                "icon": "\U0001f4d0"
            })

            # 6. Work order created
            wo_dir = os.path.join(SHOP_DRAWINGS_DIR, job_code, "work_orders")
            has_wo = False
            wo_status = ""
            wo_progress = ""
            if os.path.isdir(wo_dir):
                for fn in os.listdir(wo_dir):
                    if fn.endswith(".json"):
                        has_wo = True
                        try:
                            with open(os.path.join(wo_dir, fn)) as f:
                                wo_data = json.load(f)
                            wo_status = wo_data.get("status", "")
                            items = wo_data.get("items", [])
                            done = sum(1 for i in items if i.get("status") == "complete")
                            wo_progress = f"{done}/{len(items)}"
                        except Exception:
                            pass
                        break

            milestones.append({
                "key": "work_order",
                "label": "Work Order Created",
                "date": "",
                "complete": has_wo,
                "icon": "\U0001f527"
            })

            # 7. Fabrication
            fab_complete = wo_status == "complete"
            milestones.append({
                "key": "fabrication",
                "label": f"Fabrication {'Complete' if fab_complete else 'In Progress' if wo_status == 'in_progress' else 'Pending'}",
                "date": "",
                "complete": fab_complete,
                "progress": wo_progress,
                "icon": "\u2699\ufe0f"
            })

            # 8. Shipping
            milestones.append({
                "key": "shipping",
                "label": "Shipped",
                "date": project.get("shipped_date", ""),
                "complete": stage in ["complete", "delivered"],
                "icon": "\U0001f69b"
            })

            # 9. Delivered / Complete
            milestones.append({
                "key": "complete",
                "label": "Delivered",
                "date": project.get("delivered_date", ""),
                "complete": stage == "complete",
                "icon": "\u2705"
            })

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "job_code": job_code,
                "milestones": milestones,
            }))
        except Exception as e:
            logger.error(f"ProjectTimelineHandler error: {e}", exc_info=True)
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))

class ProjectToolStatusHandler(BaseHandler):
    """GET /api/project/tool-status?job_code=XXX — Return completion status
    for every toolbox card on the project page.

    Returns a dict of tool → {done: bool, pct: int, version, detail}
    so the front-end can decorate each card with a badge / mini-bar.
    """
    def get(self):
        try:
            job_code = self.get_query_argument("job_code", "").strip()
            if not job_code:
                self.write(json_encode({"ok": False, "error": "Missing job_code"}))
                return

            safe_name = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            proj_dir = os.path.join(PROJECTS_DIR, safe_name)
            tools = {}

            # ── SA Estimator ─────────────────────────────────
            current_path = os.path.join(proj_dir, "current.json")
            sa_version = 0
            sa_done = False
            if os.path.isfile(current_path):
                try:
                    with open(current_path) as f:
                        cdata = json.load(f)
                    sa_version = cdata.get("version", 1)
                    sa_done = bool(cdata.get("bom_data"))
                except Exception:
                    pass
            # Count version files
            n_versions = len(glob.glob(os.path.join(proj_dir, "v*.json")))
            tools["sa_estimator"] = {
                "done": sa_done,
                "pct": 100 if sa_done else 0,
                "version": sa_version,
                "n_versions": n_versions,
                "detail": f"v{sa_version}" if sa_version else "Not started",
            }

            # ── TC Estimator ─────────────────────────────────
            tc_done = False
            tc_version = 0
            tc_detail = "Not started"
            # Check both locations for TC quote data
            tc_path_proj = os.path.join(proj_dir, "tc_quote.json")
            tc_path_dir = os.path.join(DATA_DIR, "tc_quotes", f"{safe_name}.json")
            tc_path = tc_path_proj if os.path.isfile(tc_path_proj) else tc_path_dir
            if os.path.isfile(tc_path):
                try:
                    with open(tc_path) as f:
                        tc_data = json.load(f)
                    tc_version = tc_data.get("version", 1)
                    tc_done = True
                    tc_detail = f"Done v{tc_version}"
                except Exception:
                    tc_done = True
                    tc_version = 1
                    tc_detail = "Done v1"
            tools["tc_estimator"] = {
                "done": tc_done,
                "pct": 100 if tc_done else 0,
                "version": tc_version,
                "detail": tc_detail,
            }

            # ── BOM ──────────────────────────────────────────
            tools["bom"] = {
                "done": sa_done,
                "pct": 100 if sa_done else 0,
                "version": sa_version,
                "detail": "Calculated" if sa_done else "Pending",
            }

            # ── Shop Drawings ────────────────────────────────
            interactive_sources = _load_interactive_sources(job_code)
            n_drawings = len(interactive_sources)
            revisions = _load_revisions(job_code)
            last_rev = revisions[0].get("revision", "-") if revisions else None
            sd_pct = min(100, n_drawings * 50)  # 2 drawings = 100%
            tools["shop_drawings"] = {
                "done": n_drawings >= 2,
                "pct": sd_pct,
                "version": last_rev,
                "detail": f"{n_drawings} drawing{'s' if n_drawings != 1 else ''}" + (f" (Rev {last_rev})" if last_rev else ""),
            }

            # ── Work Orders ──────────────────────────────────
            wo_pct = 0
            wo_detail = "Not created"
            wo_done = False
            try:
                if HAS_SHOP_DRAWINGS:
                    wos = list_work_orders(SHOP_DRAWINGS_DIR, job_code)
                    total_items = 0
                    completed_items = 0
                    for wo_info in wos:
                        wo_id = wo_info.get("work_order_id") or wo_info.get("wo_id", "")
                        wo_obj = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
                        if wo_obj:
                            for item in (wo_obj.items if hasattr(wo_obj, 'items') else []):
                                total_items += 1
                                st = item.status if hasattr(item, 'status') else ""
                                if st == STATUS_COMPLETE or (hasattr(item, 'loading_status') and item.loading_status == "delivered"):
                                    completed_items += 1
                        # Also use summary data if load failed
                        if not wo_obj and wo_info.get("total_items", 0) > 0:
                            total_items += wo_info["total_items"]
                            completed_items += wo_info.get("completed_items", 0)
                    if total_items > 0:
                        wo_pct = int(completed_items / total_items * 100)
                        wo_done = wo_pct == 100
                        wo_detail = f"{completed_items}/{total_items} items"
                    elif wos:
                        wo_detail = f"{len(wos)} WO{'s' if len(wos)!=1 else ''} (loading...)"
            except Exception:
                pass
            tools["work_orders"] = {
                "done": wo_done,
                "pct": wo_pct,
                "detail": wo_detail,
            }

            # ── QC Dashboard ─────────────────────────────────
            tools["qc"] = {
                "done": wo_done,
                "pct": wo_pct,
                "detail": wo_detail,
            }

            # ── Quote Editor ─────────────────────────────────
            # Check if a quote document exists
            quote_dir = os.path.join(proj_dir, "docs", "quotes")
            n_quotes = 0
            if os.path.isdir(quote_dir):
                n_quotes = len([f for f in os.listdir(quote_dir)
                               if os.path.isfile(os.path.join(quote_dir, f)) and not f.startswith("_")])
            tools["quote"] = {
                "done": n_quotes > 0,
                "pct": 100 if n_quotes > 0 else (50 if sa_done else 0),
                "detail": f"{n_quotes} quote{'s' if n_quotes!=1 else ''}" if n_quotes else ("Ready" if sa_done else "Pending BOM"),
            }

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({"ok": True, "tools": tools}))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class ProjectArchiveDocHandler(BaseHandler):
    """POST /api/project/docs/archive — Archive a document (move to archive subfolder)."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            category = body.get("category", "").lower()
            filename = body.get("filename", "").strip()

            safe_name = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            safe_cat = re.sub(r"[^a-zA-Z0-9_\-]", "_", category)
            safe_file = os.path.basename(filename)
            base_dir = os.path.realpath(os.path.join(PROJECTS_DIR, safe_name, "docs"))
            src = os.path.realpath(os.path.join(base_dir, safe_cat, safe_file))
            # Prevent path traversal
            if not src.startswith(base_dir):
                self.set_status(403)
                self.write(json_encode({"ok": False, "error": "Access denied"}))
                return
            archive_dir = os.path.join(base_dir, safe_cat, "_archive")
            os.makedirs(archive_dir, exist_ok=True)

            if not os.path.isfile(src):
                self.write(json_encode({"ok": False, "error": "File not found"}))
                return

            # Add timestamp to archived filename to prevent overwrites
            ts = int(time.time())
            base, ext = os.path.splitext(safe_file)
            archived_name = f"{base}_archived_{ts}{ext}"
            dst = os.path.join(archive_dir, archived_name)

            os.rename(src, dst)

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({"ok": True, "archived_as": archived_name}))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"error": str(e)}))


class ProjectArchivedDocsHandler(BaseHandler):
    """POST /api/project/docs/archived — List archived documents for a category."""
    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            category = body.get("category", "").lower()

            safe_name = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            safe_cat = re.sub(r"[^a-zA-Z0-9_\-]", "_", category)
            archive_dir = os.path.join(PROJECTS_DIR, safe_name, "docs", safe_cat, "_archive")

            files = []
            if os.path.isdir(archive_dir):
                for fname in sorted(os.listdir(archive_dir), reverse=True):
                    fpath = os.path.join(archive_dir, fname)
                    if os.path.isfile(fpath):
                        stat = os.stat(fpath)
                        files.append({
                            "filename": fname,
                            "category": category,
                            "size": stat.st_size,
                            "url": f"/project-files/{safe_name}/{category}/_archive/{fname}",
                            "archived_at": datetime.datetime.fromtimestamp(stat.st_mtime).isoformat(),
                        })

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({"ok": True, "files": files}))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"error": str(e)}))


