def _shop_drawing_project_dir(job_code):
    """Get or create the shop drawing directory for a project."""
    safe = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
    d = os.path.join(SHOP_DRAWINGS_DIR, safe)
    os.makedirs(d, exist_ok=True)
    return d


def _load_shop_config(job_code, building_id=None):
    """Load saved ShopDrawingConfig for a project, or return None.

    If building_id is specified (e.g. "B1", "B2"), the config is enriched
    with that building's dimensions from the BOM buildings array.
    """
    d = _shop_drawing_project_dir(job_code)
    cfg_path = os.path.join(d, "config.json")
    config = None
    if os.path.isfile(cfg_path):
        with open(cfg_path) as f:
            config = json.load(f)

    if config is None:
        config = _derive_bom_config(job_code)
        if not config:
            return None

    if building_id:
        config = _enrich_config_for_building(job_code, config, building_id)

    return config


def _load_buildings_list(job_code):
    """Load the buildings array from BOM data for a project.

    Returns a list of dicts with building_id, width_ft, length_ft,
    clear_height_ft, slope_deg, n_frames, purlin_spacing_ft, etc.
    """
    safe = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
    proj_dir = os.path.join(PROJECTS_DIR, safe)
    if not os.path.isdir(proj_dir):
        return []

    # Find version files
    version_files = sorted(
        [f for f in os.listdir(proj_dir) if f.startswith("v") and f.endswith(".json")],
        reverse=True
    )
    if not version_files:
        sub_versions_dir = os.path.join(proj_dir, "versions")
        if os.path.isdir(sub_versions_dir):
            version_files = sorted(
                [f for f in os.listdir(sub_versions_dir) if f.endswith(".json")],
                reverse=True
            )
            proj_dir = sub_versions_dir
    if not version_files and os.path.isfile(os.path.join(PROJECTS_DIR, safe, "current.json")):
        version_files = ["current.json"]
        proj_dir = os.path.join(PROJECTS_DIR, safe)

    for vf in version_files:
        try:
            with open(os.path.join(proj_dir, vf)) as f:
                data = json.load(f)
            bom_result = data.get("bom_result") or data.get("bom_data") or data.get("results", {})
            bom_buildings = []
            if bom_result:
                bom_buildings = bom_result.get("buildings", [])
            if not bom_buildings:
                bom_buildings = data.get("buildings", [])
            if bom_buildings:
                # Also try to load the INPUT buildings (from SA calc form)
                # which have fields like footing_depth_ft at the top level,
                # whereas BOM output buildings store them in geometry.
                input_buildings = data.get("buildings", [])
                input_map = {}
                for ib in input_buildings:
                    # Input buildings use "id" like "bldg_1", "bldg_2"
                    idx = ib.get("id", "")
                    input_map[idx] = ib

                result = []
                for i, b in enumerate(bom_buildings):
                    # BOM output has many fields in geometry sub-object;
                    # check geometry as fallback for fields not at top level
                    geom = b.get("geometry", {})
                    # Also check the input building for values not in BOM output
                    inp = input_map.get(f"bldg_{i+1}", {})
                    result.append({
                        "building_id": f"B{i + 1}",
                        "index": i,
                        "width_ft": b.get("width_ft", 40.0),
                        "length_ft": b.get("length_ft", 120.0),
                        "clear_height_ft": b.get("clear_height_ft", 14.0),
                        "slope_deg": b.get("slope_deg") or geom.get("slope_deg", 1.19),
                        "n_frames": b.get("n_frames") or geom.get("n_frames", 5),
                        "purlin_spacing_ft": b.get("purlin_spacing_ft") or b.get("purlin_spacing_override") or geom.get("purlin_spacing_ft", 5.0),
                        "frame_type": geom.get("frame_type") or ("tee" if b.get("width_ft", 40) <= 45 else "dbl_col"),
                        "overhang_ft": b.get("overhang_ft") or geom.get("overhang_ft", 0.0),
                        "embedment_ft": b.get("embedment_ft", 4.333),
                        "footing_depth_ft": b.get("footing_depth_ft") or geom.get("footing_depth_ft") or inp.get("footing_depth_ft") or 10.0,
                        "col_positions": b.get("col_positions") or geom.get("col_positions", []),
                        "bay_sizes": b.get("bay_sizes") or geom.get("bay_sizes_list", []),
                        "building_name": b.get("building_name", f"Building {i+1}"),
                        "include_rafter_rebar": b.get("include_rafter_rebar", False),
                        "rebar_col_size": b.get("rebar_col_size", "auto"),
                        "column_mode": b.get("column_mode") or geom.get("column_mode", "auto"),
                        # Rafter/purlin drawing fields from BOM geometry
                        "purlin_type": geom.get("purlin_type") or inp.get("purlin_type", "Z"),
                        "angled_purlins": geom.get("angled_purlins") or inp.get("angled_purlins", False),
                        "purlin_angle_deg": geom.get("purlin_angle_deg") or inp.get("purlin_angle_deg", 0),
                        "roofing_overhang_ft": geom.get("roofing_overhang_ft") or inp.get("roofing_overhang_ft", 0.0),
                        "n_purlin_lines": geom.get("n_purlin_lines", 0),
                        "split_pos_ft": geom.get("split_pos_ft", 0.0),
                        # Column drawing fields from BOM geometry
                        "above_grade_ft": geom.get("above_grade_ft") or inp.get("above_grade_ft", 0.0),
                        "cut_allowance_in": geom.get("cut_allowance_in") or inp.get("cut_allowance_in", 6.0),
                        "col_ht_ft": geom.get("col_ht_ft", 0.0),
                        "reinforced": b.get("reinforced", True),
                        "rebar_beam_size": b.get("rebar_beam_size", "auto"),
                        # Column positioning (from input buildings)
                        "column_spacing_ft": inp.get("column_spacing_ft") or inp.get("column_spacing", 25.0),
                        "column_count_manual": inp.get("column_count_manual", 1),
                        "column_positions_manual": inp.get("column_positions_manual", ""),
                        "include_back_wall": b.get("include_back_wall") or inp.get("include_back_wall", False),
                        "front_col_position_ft": inp.get("front_col_position_ft", 0.0),
                    })
                return result
        except Exception:
            continue
    return []


def _enrich_config_for_building(job_code, config, building_id):
    """Overlay building-specific dimensions onto the config dict.

    building_id is like "B1", "B2", etc.
    """
    buildings = _load_buildings_list(job_code)
    if not buildings:
        return config

    # Find matching building
    target = None
    for b in buildings:
        if b["building_id"] == building_id:
            target = b
            break
    if not target:
        return config

    enriched = dict(config)
    enriched["building_id"] = building_id
    enriched["building_width_ft"] = target["width_ft"]
    enriched["width_ft"] = target["width_ft"]
    enriched["building_length_ft"] = target["length_ft"]
    enriched["length_ft"] = target["length_ft"]
    enriched["clear_height_ft"] = target["clear_height_ft"]
    enriched["roof_pitch_deg"] = target["slope_deg"]
    enriched["pitch_deg"] = target["slope_deg"]
    enriched["slope_deg"] = target["slope_deg"]
    enriched["n_frames"] = target["n_frames"]
    enriched["purlin_spacing_ft"] = target["purlin_spacing_ft"]
    enriched["frame_type"] = target["frame_type"]
    enriched["overhang_ft"] = target["overhang_ft"]
    enriched["embedment_ft"] = target["embedment_ft"]
    enriched["footing_depth_ft"] = target.get("footing_depth_ft", 10.0)
    enriched["building_name"] = target.get("building_name", building_id)
    # Column drawing: above-grade and cut allowance
    if target.get("above_grade_ft"):
        enriched["above_grade_ft"] = target["above_grade_ft"]
    if target.get("cut_allowance_in"):
        enriched["cut_allowance_in"] = target["cut_allowance_in"]
    if target.get("col_ht_ft"):
        enriched["col_ht_ft"] = target["col_ht_ft"]
    enriched["reinforced"] = target.get("reinforced", True)
    # Rafter drawing: purlin type, angled purlins, column positioning
    if target.get("purlin_type"):
        enriched["purlin_type"] = target["purlin_type"]
    enriched["angled_purlins"] = target.get("angled_purlins", False)
    if target.get("purlin_angle_deg"):
        enriched["purlin_angle_deg"] = target["purlin_angle_deg"]
    enriched["column_mode"] = target.get("column_mode", "auto")
    if target.get("column_spacing_ft"):
        enriched["column_spacing_ft"] = target["column_spacing_ft"]
    if target.get("column_count_manual"):
        enriched["column_count_manual"] = target["column_count_manual"]
    if target.get("column_positions_manual"):
        enriched["column_positions_manual"] = target["column_positions_manual"]
    enriched["include_back_wall"] = target.get("include_back_wall", False)
    enriched["back_wall"] = target.get("include_back_wall", False)
    if target.get("front_col_position_ft"):
        enriched["front_col_position_ft"] = target["front_col_position_ft"]
    if target.get("split_pos_ft"):
        enriched["split_pos_ft"] = target["split_pos_ft"]
    # Purlin drawing: purlin lines, roofing overhang
    if target.get("n_purlin_lines"):
        enriched["n_purlin_lines"] = target["n_purlin_lines"]
    if target.get("roofing_overhang_ft"):
        enriched["roofing_overhang_ft"] = target["roofing_overhang_ft"]
    enriched["rebar_beam_size"] = target.get("rebar_beam_size", "auto")
    # Purlin detail fields
    if target.get("max_purlin_length_ft"):
        enriched["max_purlin_length_ft"] = target["max_purlin_length_ft"]
    if target.get("z_extension_ft"):
        enriched["z_extension_ft"] = target["z_extension_ft"]
    if target.get("z_eave_overhang_in"):
        enriched["z_eave_overhang_in"] = target["z_eave_overhang_in"]
    if target.get("purlin_cost_per_ft_z"):
        enriched["purlin_cost_per_ft_z"] = target["purlin_cost_per_ft_z"]
    if target.get("purlin_cost_per_ft_c"):
        enriched["purlin_cost_per_ft_c"] = target["purlin_cost_per_ft_c"]
    # Solar fields
    enriched["is_solar"] = target.get("solar_mode", False)
    if target.get("solar_mode"):
        for sf in ("solar_orientation", "solar_panel_width_mm", "solar_panel_length_mm",
                    "solar_mount_hole_edge_mm", "solar_mount_hole_inset_mm",
                    "solar_panels_across", "solar_panels_along",
                    "solar_gap_width_in", "solar_gap_length_in",
                    "solar_edge_clearance_in", "solar_dim_mode",
                    "solar_slope_deg", "solar_install_per_panel"):
            if target.get(sf) is not None:
                enriched[sf] = target[sf]
    # Override any stale rafter-derived values so building-specific data always wins
    enriched["_rafter_width_ft"] = target["width_ft"]
    enriched["_rafter_clear_height_ft"] = target["clear_height_ft"]
    enriched["_rafter_pitch"] = target["slope_deg"]
    # Column count for shop drawing title block
    # Use BOM geometry if available; otherwise calculate from building params
    # (same formula as BOM: n_frames × columns_per_rafter)
    geom = target.get("geometry", {})
    n_frames = target["n_frames"]
    if geom.get("n_struct_cols"):
        enriched["num_columns"] = geom["n_struct_cols"]
    else:
        # Calculate columns per rafter the same way the BOM does
        raft_n_cols, _ = calc_rafter_columns(
            target["width_ft"],
            column_mode=target.get("column_mode", "auto"),
            column_spacing_ft=target.get("column_spacing_ft", 25.0),
            column_count_manual=target.get("column_count_manual", 1),
            column_positions_manual=target.get("column_positions_manual", ""),
            include_back_wall=target.get("include_back_wall", False),
            front_col_position_ft=target.get("front_col_position_ft", 0.0),
        )
        enriched["num_columns"] = n_frames * raft_n_cols
    enriched["include_rafter_rebar"] = target.get("include_rafter_rebar", False)
    enriched["col_rebar_size"] = target.get("rebar_col_size", "auto")
    if target.get("col_positions"):
        enriched["col_positions"] = target["col_positions"]
    if target.get("bay_sizes"):
        enriched["bay_sizes"] = target["bay_sizes"]
    return enriched


def _save_shop_config(job_code, cfg_dict):
    """Save ShopDrawingConfig dict for a project."""
    d = _shop_drawing_project_dir(job_code)
    cfg_path = os.path.join(d, "config.json")
    with open(cfg_path, "w") as f:
        json.dump(cfg_dict, f, indent=2, default=str)


def _load_generation_log(job_code):
    """Load the most recent generation log, if any."""
    d = _shop_drawing_project_dir(job_code)
    safe = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
    log_path = os.path.join(d, "pdfs", f"{job_code}_generation_log.json")
    if os.path.isfile(log_path):
        with open(log_path) as f:
            return json.load(f)
    # Fallback: scan for any generation_log.json
    pdfs_dir = os.path.join(d, "pdfs")
    if os.path.isdir(pdfs_dir):
        for fname in os.listdir(pdfs_dir):
            if fname.endswith("_generation_log.json"):
                with open(os.path.join(pdfs_dir, fname)) as f:
                    return json.load(f)
    return None


def _load_revisions(job_code):
    """Load revision history for a project."""
    d = _shop_drawing_project_dir(job_code)
    rev_path = os.path.join(d, "revisions.json")
    if os.path.isfile(rev_path):
        with open(rev_path) as f:
            return json.load(f)
    return []


def _save_revision(job_code, rev_entry):
    """Append a revision entry."""
    d = _shop_drawing_project_dir(job_code)
    rev_path = os.path.join(d, "revisions.json")
    revisions = _load_revisions(job_code)
    revisions.insert(0, rev_entry)
    with open(rev_path, "w") as f:
        json.dump(revisions, f, indent=2, default=str)
    return revisions


def _load_interactive_sources(job_code):
    """Load the interactive-source manifest for a project's shop drawings.

    Returns a dict of {filename: {drawing_type, saved_at, source}} for every
    PDF that was created by the Interactive Builder.  Legacy / unknown PDFs
    are intentionally excluded so they never appear in the gallery.
    """
    d = _shop_drawing_project_dir(job_code)
    manifest_path = os.path.join(d, "pdfs", "_interactive_sources.json")
    if os.path.isfile(manifest_path):
        with open(manifest_path) as f:
            return json.load(f)
    return {}


def _register_interactive_source(job_code, filename, drawing_type, building_id="B1"):
    """Record that *filename* was saved by the Interactive Builder."""
    sources = _load_interactive_sources(job_code)
    sources[filename] = {
        "drawing_type": drawing_type,
        "building_id": building_id,
        "saved_at": datetime.datetime.now().isoformat(),
        "source": "interactive",
    }
    d = _shop_drawing_project_dir(job_code)
    manifest_path = os.path.join(d, "pdfs", "_interactive_sources.json")
    os.makedirs(os.path.dirname(manifest_path), exist_ok=True)
    with open(manifest_path, "w") as f:
        json.dump(sources, f, indent=2, default=str)
    return sources


def _derive_bom_config(job_code):
    """Try to load BOM data for a project and derive ShopDrawingConfig from it."""
    if not HAS_SHOP_DRAWINGS:
        return {}
    safe = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
    proj_dir = os.path.join(PROJECTS_DIR, safe)

    # Look for the latest saved version with BOM data
    # Version files are stored directly in proj_dir as v1.json, v2.json, etc.
    # Also check a "versions" subdirectory for backward compatibility
    versions_dir = proj_dir
    if not os.path.isdir(versions_dir):
        return {}

    # Find most recent version file (v*.json pattern), also include current.json as fallback
    version_files = sorted(
        [f for f in os.listdir(versions_dir) if f.startswith("v") and f.endswith(".json")],
        reverse=True
    )
    # Also check "versions" subdirectory if no v*.json found in proj_dir
    if not version_files:
        sub_versions_dir = os.path.join(proj_dir, "versions")
        if os.path.isdir(sub_versions_dir):
            version_files = sorted(
                [f for f in os.listdir(sub_versions_dir) if f.endswith(".json")],
                reverse=True
            )
            versions_dir = sub_versions_dir
    # Fallback to current.json
    if not version_files and os.path.isfile(os.path.join(proj_dir, "current.json")):
        version_files = ["current.json"]

    for vf in version_files:
        try:
            with open(os.path.join(versions_dir, vf)) as f:
                data = json.load(f)

            # Try multiple keys for BOM data (different save formats)
            bom_result = data.get("bom_result") or data.get("bom_data") or data.get("results", {})

            # Build geometry dict from buildings array if geometry key is missing
            if bom_result and "geometry" not in bom_result:
                bom_buildings = bom_result.get("buildings", [])
                # Also check top-level buildings array (SA save format)
                if not bom_buildings:
                    bom_buildings = data.get("buildings", [])
                if bom_buildings and len(bom_buildings) > 0:
                    b = bom_buildings[0]
                    bom_result["geometry"] = {
                        "width_ft": b.get("width_ft", 40.0),
                        "length_ft": b.get("length_ft", 120.0),
                        "clear_height_ft": b.get("clear_height_ft", 14.0),
                        "slope_deg": b.get("slope_deg", 1.19),
                        "n_frames": b.get("n_frames", 5),
                        "overhang_ft": b.get("overhang_ft", 0.0),
                        "embedment_ft": b.get("embedment_ft", 4.333),
                        "footing_depth_ft": b.get("footing_depth_ft", 0.0),
                        "purlin_spacing_ft": b.get("purlin_spacing_ft") or b.get("purlin_spacing_override") or 5.0,
                        "frame_type": "tee" if b.get("width_ft", 40) <= 45 else "dbl_col",
                        "col_positions": b.get("col_positions", []),
                    }

            if bom_result and "geometry" in bom_result:
                # Load project metadata for project_info
                meta_path = os.path.join(proj_dir, "metadata.json")
                project_info = {}
                if os.path.isfile(meta_path):
                    with open(meta_path) as mf:
                        meta = json.load(mf)
                    customer = meta.get("customer", {})
                    customer_name = customer.get("name", "") if isinstance(customer, dict) else str(customer)
                    location = meta.get("location", {})
                    loc_str = ""
                    if isinstance(location, dict):
                        loc_str = ", ".join(filter(None, [location.get("city", ""), location.get("state", "")]))
                    else:
                        loc_str = str(location)
                    project_info = {
                        "job_code": job_code,
                        "project_name": meta.get("project_name", ""),
                        "customer_name": customer_name,
                        "location": loc_str,
                    }
                cfg = ShopDrawingConfig.from_bom_data(bom_result, project_info)
                return cfg.to_dict()
        except Exception:
            continue

    return {}



def _build_purlin_groups_for_building(job_code, building_id, config_dict):
    """Build purlin group data for the purlin drawing from BOM data."""
    _PS = {
        8:  {'depth': 8,  'topFlange': 2.75, 'botFlange': 2.75, 'lip': 0.625, 'coilWidth': 14.75},
        10: {'depth': 10, 'topFlange': 3.25, 'botFlange': 3.25, 'lip': 0.625, 'coilWidth': 17.875},
        12: {'depth': 12, 'topFlange': 3.5,  'botFlange': 3.5,  'lip': 0.75,  'coilWidth': 20.125},
    }
    _GT = {'12GA': 0.105, '14GA': 0.075}
    _GL = {
        '12GA': {8: 5.20, 10: 6.30, 12: 7.43},
        '14GA': {8: 3.70, 10: 4.50, 12: 5.30},
    }

    width_ft = config_dict.get('building_width_ft', 40.0)
    length_ft = config_dict.get('building_length_ft', 120.0)
    n_frames = config_dict.get('n_frames', 5)
    spacing_ft = config_dict.get('purlin_spacing_ft', 5.0)
    depth = 12
    gauge = config_dict.get('purlin_gauge', '12GA')
    frame_type = config_dict.get('frame_type', 'tee')
    span_ft = width_ft if frame_type == 'tee' else width_ft / 2.0

    bay_sizes = config_dict.get('bay_sizes', [])
    if not bay_sizes and n_frames > 1:
        bay_size = length_ft / (n_frames - 1)
        bay_sizes = [bay_size] * (n_frames - 1)

    purlin_groups_raw = []
    if HAS_SHOP_DRAWINGS:
        try:
            from shop_drawings.config import calc_purlin_groups
            overhang_ft = config_dict.get('overhang_ft', 0.0)
            purlin_groups_raw = calc_purlin_groups(
                building_length_ft=length_ft,
                bay_sizes=bay_sizes,
                overhang_ft=overhang_ft,
            )
        except Exception:
            pass

    groups = []
    spec = _PS.get(depth, _PS[12])
    thick = _GT.get(gauge, 0.105)
    lbs_ft = _GL.get(gauge, {}).get(depth, 7.43)
    spacing_in = spacing_ft * 12
    qty_per_bay = max(1, int(span_ft * 12 / spacing_in) + 1)

    if purlin_groups_raw:
        for pg in purlin_groups_raw:
            g_len_ft = pg.get('length_ft', span_ft)
            g_type = pg.get('type', 'middle')
            mark = 'Z%d-%s-G%d' % (depth, gauge.replace('GA', ''), pg.get('group', 1))
            label = '%d" Z-Purlin @ %d\'' % (depth, int(g_len_ft))
            g_data = {
                'group': pg.get('group', 1), 'label': label, 'type': g_type,
                'depth': depth, 'gauge': gauge, 'thickness': thick,
                'span_ft': round(g_len_ft, 2), 'spacing_ft': spacing_ft,
                'qty': qty_per_bay,
                'topFlange': spec['topFlange'], 'botFlange': spec['botFlange'],
                'lip': spec['lip'], 'coilWidth': spec['coilWidth'],
                'lbs_per_ft': lbs_ft, 'mark': mark,
            }
            # Pass splice data through to the interactive drawing
            if pg.get('needs_splice'):
                g_data['needs_splice'] = True
                sp = pg.get('splice', {})
                if sp:
                    g_data['splice_position_ft'] = sp.get('position_ft', 0)
                    g_data['splice_overlap_in'] = sp.get('overlap_in', 6)
                    g_data['splice_tek_screws'] = sp.get('tek_screws', 8)
            # Pass facing info for Z-purlin direction indicators
            g_data['is_first'] = pg.get('is_first', False)
            g_data['is_last'] = pg.get('is_last', False)
            g_data['facing'] = 'right' if pg.get('is_first') else (
                'left' if pg.get('is_last') else 'alternating')
            groups.append(g_data)
    else:
        mark = 'Z%d-%s' % (depth, gauge.replace('GA', ''))
        groups.append({
            'group': 1,
            'label': '%d" Z-Purlin @ %d\'' % (depth, int(span_ft)),
            'type': 'standard', 'depth': depth, 'gauge': gauge,
            'thickness': thick, 'span_ft': round(span_ft, 2),
            'spacing_ft': spacing_ft, 'qty': qty_per_bay,
            'topFlange': spec['topFlange'], 'botFlange': spec['botFlange'],
            'lip': spec['lip'], 'coilWidth': spec['coilWidth'],
            'lbs_per_ft': lbs_ft, 'mark': mark,
        })

    # Eave strut — REMOVED per PURLIN_RULES.md §9.4
    # Front/back purlins ARE the eave. No separate eave strut.

    return groups


class ColumnInteractiveHandler(BaseHandler):
    """GET /shop-drawings/{job_code}/column — Interactive Column Drawing."""
    def get(self, job_code):
        try:
            from templates.column_interactive import COLUMN_DRAWING_HTML

            # Load project config from saved BOM (with optional building context)
            building_id = self.get_argument("building", "B1")
            config_dict = _load_shop_config(job_code, building_id=building_id)
            if not config_dict:
                config_dict = {"job_code": job_code}
            config_dict.setdefault("job_code", job_code)
            config_dict.setdefault("building_id", building_id)

            # Load project metadata
            proj_dir = os.path.join(PROJECTS_DIR, job_code)
            meta_path = os.path.join(proj_dir, "metadata.json")
            if os.path.isfile(meta_path):
                with open(meta_path) as f:
                    meta = json.load(f)
                config_dict.setdefault("project_name", meta.get("project_name", ""))
                # customer_name is nested: metadata.customer.name
                cust_name = meta.get("customer_name", "") or (meta.get("customer", {}).get("name", ""))
                config_dict.setdefault("customer_name", cust_name)

            html = COLUMN_DRAWING_HTML
            html = html.replace("{{JOB_CODE}}", _html_escape(job_code))
            html = html.replace("{{COLUMN_CONFIG_JSON}}", _safe_json_embed(config_dict))
            self.set_header("Content-Type", "text/html")
            self.write(html)


        except Exception as e:
            logger.error(f"{self.__class__.__name__}.{self.request.method}() error: {e}", exc_info=True)
            self.set_status(500)
            self.write(f"<h2>Error</h2><p>{html.escape(str(e))}</p>")
