class WorkOrderPageHandler(BaseHandler):
    """GET /work-orders/{job_code} — Work order tracking page."""
    required_roles = ["god_mode", "admin", "project_manager", "estimator", "shop_foreman", "shop_manager", "foreman", "shop"]

    def get(self, job_code):
        try:
            from templates.work_orders import WORK_ORDERS_HTML
            html = WORK_ORDERS_HTML.replace("{{JOB_CODE}}", _html_escape(job_code))
            self.render_with_nav(html, active_page="workorders", job_code=job_code,
                                    breadcrumbs=[("Dashboard", "/"), ("Projects", "/projects"), (job_code, f"/project/{job_code}"), ("Work Orders", "")])


        except Exception as e:
            logger.error(f"{self.__class__.__name__}.{self.request.method}() error: {e}", exc_info=True)
            self.set_status(500)
            self.write(f"<h2>Error</h2><p>{html.escape(str(e))}</p>")
class WorkOrderCreateHandler(BaseHandler):
    """POST /api/work-orders/create — Create a new work order from shop drawings."""
    required_roles = ["god_mode", "admin", "project_manager", "estimator", "shop_foreman", "shop_manager", "foreman"]

    def post(self):
        try:
            if not HAS_SHOP_DRAWINGS:
                self.write(json_encode({"ok": False, "error": "Shop drawing module not available"}))
                return

            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            if not job_code:
                self.write(json_encode({"ok": False, "error": "Missing job_code"}))
                return

            # Get latest revision from generation history
            revisions = _load_revisions(job_code)
            revision = revisions[0].get("revision", "-") if revisions else "-"

            # Get current config for component counts
            cfg_dict = _load_shop_config(job_code) or _derive_bom_config(job_code)
            if not cfg_dict:
                self.write(json_encode({"ok": False, "error": "No config found — generate shop drawings first"}))
                return

            # Get drawing files list
            d = _shop_drawing_project_dir(job_code)
            pdfs_dir = os.path.join(d, "pdfs")
            drawing_files = []
            if os.path.isdir(pdfs_dir):
                drawing_files = [{"filename": f} for f in os.listdir(pdfs_dir) if f.endswith(".pdf")]

            created_by = body.get("created_by", self.get_current_user() or "system")

            # ── Pull project info from SA/TC chain ──
            project_name = body.get("project_name", "")
            customer_name = body.get("customer_name", "")
            priority = body.get("priority", "normal")
            if priority not in ("urgent", "high", "normal", "low"):
                priority = "normal"
            due_date = body.get("due_date", "")
            delivery_date = body.get("delivery_date", "")
            ship_to = body.get("ship_to", "")
            machine_id = body.get("machine_id", "")
            operator = body.get("operator", "")
            total_weight_lbs = 0.0
            total_sell = 0.0
            building_specs = ""

            # Try to load from project metadata/versions for real BOM data
            try:
                safe_jc = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
                proj_dir = os.path.join(PROJECTS_DIR, safe_jc)
                # Find latest version file
                version_files = sorted(
                    [f for f in os.listdir(proj_dir) if f.startswith("v") and f.endswith(".json")],
                    reverse=True
                ) if os.path.isdir(proj_dir) else []
                if not version_files and os.path.isfile(os.path.join(proj_dir, "current.json")):
                    version_files = ["current.json"]
                if version_files:
                    with open(os.path.join(proj_dir, version_files[0])) as f:
                        proj_data = json.load(f)
                    # Extract project info
                    if not project_name:
                        project_name = proj_data.get("project_name", "")
                    if not customer_name:
                        customer_name = proj_data.get("customer_name", "")
                    # Extract BOM results
                    bom_result = proj_data.get("bom_result") or proj_data.get("results", {})
                    if bom_result:
                        total_weight_lbs = float(bom_result.get("total_weight_lbs", 0) or 0)
                        total_sell = float(bom_result.get("total_sell", 0) or 0)
                    # Extract building specs
                    buildings = proj_data.get("buildings") or bom_result.get("buildings", [])
                    if buildings and len(buildings) > 0:
                        b = buildings[0]
                        w = b.get("width_ft", 0)
                        l = b.get("length_ft", 0)
                        h = b.get("clear_height_ft", 0)
                        ft = cfg_dict.get("frame_type", "tee")
                        ft_label = "TEE" if ft == "tee" else "DBL-COL"
                        building_specs = f"{int(w)}'x{int(l)}'x{int(h)}' {ft_label}"
            except Exception:
                pass  # Non-critical — proceed with whatever we have

            wo = create_work_order(
                job_code=job_code,
                revision=revision,
                created_by=created_by,
                drawing_files=drawing_files,
                config_dict=cfg_dict,
                project_name=project_name,
                customer_name=customer_name,
                priority=priority,
                due_date=due_date,
                delivery_date=delivery_date,
                ship_to=ship_to,
                total_weight_lbs=total_weight_lbs,
                total_sell=total_sell,
                building_specs=building_specs,
                machine_id=machine_id,
                operator=operator,
            )

            save_work_order(SHOP_DRAWINGS_DIR, wo)

            # Check material availability from coil inventory (Rec 6)
            material_warnings = []
            try:
                inv = load_inventory()
                coils = inv.get("coils", {})
                wo_weight = total_weight_lbs  # from BOM data loaded above
                if wo_weight > 0 and coils:
                    # Sum available stock across all coils matching the gauge from config
                    required_gauge = str(cfg_dict.get("gauge", "10"))
                    available_lbs = sum(
                        float(c.get("stock_lbs", 0))
                        for c in (coils.values() if isinstance(coils, dict) else coils)
                        if str(c.get("gauge", "")) == required_gauge
                    )
                    if wo_weight > available_lbs:
                        material_warnings.append(
                            f"Warning: Work order needs ~{wo_weight:.0f} lbs but only {available_lbs:.0f} lbs of {required_gauge}GA coil in stock"
                        )
                    # Also check total stock regardless of gauge
                    total_available = sum(
                        float(c.get("stock_lbs", 0))
                        for c in (coils.values() if isinstance(coils, dict) else coils)
                    )
                    if wo_weight > total_available:
                        material_warnings.append(
                            f"Warning: Total coil inventory ({total_available:.0f} lbs) is below work order weight ({wo_weight:.0f} lbs)"
                        )
            except Exception:
                pass  # Non-critical — work order is still created

            # ── Inventory Allocation: commit coil stock to this WO ──
            allocation_ids = []
            material_status = ""
            try:
                if total_weight_lbs > 0:
                    inv = load_inventory()
                    coils = inv.get("coils", {})
                    required_gauge = str(cfg_dict.get("gauge", "10"))
                    remaining_need = total_weight_lbs

                    # Find matching coils sorted by stock descending
                    matching_coils = sorted(
                        [(cid, c) for cid, c in (coils.items() if isinstance(coils, dict) else [])
                         if str(c.get("gauge", "")) == required_gauge],
                        key=lambda x: float(x[1].get("stock_lbs", 0)) - float(x[1].get("committed_lbs", 0)),
                        reverse=True
                    )

                    alloc_path = os.path.join(DATA_DIR, "inventory_allocations.json")
                    allocs = []
                    if os.path.isfile(alloc_path):
                        with open(alloc_path) as f:
                            allocs = json.load(f)

                    for coil_id, coil in matching_coils:
                        if remaining_need <= 0:
                            break
                        available = float(coil.get("stock_lbs", 0)) - float(coil.get("committed_lbs", 0))
                        if available <= 0:
                            continue
                        alloc_qty = min(available, remaining_need)

                        # Commit the stock
                        coil["committed_lbs"] = float(coil.get("committed_lbs", 0)) + alloc_qty

                        alloc_id = f"ALLOC-{len(allocs)+1:04d}"
                        allocs.append({
                            "allocation_id": alloc_id,
                            "coil_id": coil_id,
                            "job_code": job_code,
                            "quantity_lbs": alloc_qty,
                            "consumed_lbs": 0,
                            "status": "active",
                            "work_order_ref": wo.work_order_id,
                            "notes": f"Auto-allocated at WO creation",
                            "date": datetime.datetime.now().isoformat(),
                        })
                        allocation_ids.append(alloc_id)
                        remaining_need -= alloc_qty

                    save_inventory(inv)
                    with open(alloc_path, "w") as f:
                        json.dump(allocs, f, indent=2)

                    if remaining_need <= 0:
                        material_status = "allocated"
                    elif allocation_ids:
                        material_status = "partial"
                    else:
                        material_status = "awaiting_material"

                    # Update WO with allocation info
                    wo.allocation_ids = allocation_ids
                    wo.material_status = material_status
                    if material_status == "awaiting_material":
                        # Mark all fabricated items as awaiting_material in notes
                        for item in wo.items:
                            if getattr(item, "item_category", "fabricated") == "fabricated":
                                item.notes = "[AWAITING MATERIAL] " + (item.notes or "")
                    save_work_order(SHOP_DRAWINGS_DIR, wo)
            except Exception as alloc_err:
                logger.warning(f"Inventory allocation failed for WO {wo.work_order_id}: {alloc_err}")
                # Non-critical — WO is still created

            self._log("created_work_order", "work_order", getattr(wo, "work_order_id", ""), {"job_code": job_code})
            self.set_header("Content-Type", "application/json")
            response = {
                "ok": True,
                "work_order": wo.to_dict(),
                "summary": wo.summary(),
            }
            if material_warnings:
                response["material_warnings"] = material_warnings
            if allocation_ids:
                response["allocations"] = allocation_ids
                response["material_status"] = material_status
            self.write(json_encode(response))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


