class WorkOrderHoldHandler(BaseHandler):
    """POST /api/work-orders/hold — Put a work order on hold or resume it."""
    required_roles = ["admin", "estimator"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            action = body.get("action", "hold")  # "hold" or "resume"
            if not job_code or not wo_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or wo_id"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            if action == "hold":
                if wo.status == STATUS_ON_HOLD:
                    self.write(json_encode({"ok": False, "error": "Already on hold"}))
                    return
                if wo.status == STATUS_COMPLETE:
                    self.write(json_encode({"ok": False, "error": "Cannot hold a completed WO"}))
                    return
                wo.notes = f"[ON HOLD] Previous status: {wo.status}. " + wo.notes
                wo.status = STATUS_ON_HOLD
            elif action == "resume":
                if wo.status != STATUS_ON_HOLD:
                    self.write(json_encode({"ok": False, "error": "Not currently on hold"}))
                    return
                # Resume to queued (admin can re-approve)
                wo.status = STATUS_QUEUED
            else:
                self.write(json_encode({"ok": False, "error": f"Unknown action: {action}"}))
                return

            save_work_order(SHOP_DRAWINGS_DIR, wo)
            self._log("work_order_" + action, "work_order", wo_id, {"job_code": job_code})

            # ── Broadcast status change via WebSocket ──
            try:
                LiveUpdateWebSocket.broadcast({
                    "type": "wo_status",
                    "action": action,
                    "data": {
                        "job_code": job_code,
                        "wo_id": wo_id,
                        "status": wo.status,
                        "timestamp": datetime.datetime.now().isoformat(),
                    }
                })
            except Exception:
                pass

            # ── Email notification: QC hold ──
            if action == "hold" and HAS_EMAIL_NOTIFICATIONS:
                try:
                    send_notification("qc_hold", context_data={
                        "job_code": job_code,
                        "wo_id": wo_id,
                        "reason": body.get("reason", "No reason provided"),
                        "held_by": self.get_current_user() or "unknown",
                    })
                except Exception as notif_err:
                    logger.warning(f"Failed to send qc_hold notification: {notif_err}")

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({"ok": True, "work_order": wo.to_dict(), "summary": wo.summary()}))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderQRScanHandler(BaseHandler):
    """POST /api/work-orders/qr-scan — Process a QR code scan (start or finish)."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            action = body.get("action", "").strip()  # "start" or "finish"
            scanned_by = body.get("scanned_by", self.get_current_user() or "shop")

            if not job_code or not item_id or not action:
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, or action"}))
                return

            if action == "start":
                result = qr_scan_start(SHOP_DRAWINGS_DIR, job_code, item_id, scanned_by)
            elif action == "finish":
                result = qr_scan_finish(SHOP_DRAWINGS_DIR, job_code, item_id, scanned_by)
                # ── Record completion in gamification engine ──
                if result.get("ok"):
                    try:
                        from shop_drawings.gamification import record_completion
                        dur = result.get("duration_minutes", 0)
                        machine = result.get("machine", "")
                        comp_type = result.get("component_type", "")
                        gam = record_completion(
                            SHOP_DRAWINGS_DIR, scanned_by, dur,
                            machine=machine, component_type=comp_type
                        )
                        result["gamification"] = gam
                    except Exception:
                        pass  # Don't break the scan if gamification fails
            else:
                self.write(json_encode({"ok": False, "error": f"Unknown action: {action}. Use 'start' or 'finish'."}))
                return

            if result.get("ok"):
                self._log("qr_scan_" + action, "work_order_item", item_id, {"job_code": job_code})
                # ── Broadcast scan event via WebSocket ──
                try:
                    LiveUpdateWebSocket.broadcast({
                        "type": "scan",
                        "action": action,
                        "data": {
                            "job_code": job_code,
                            "item_id": item_id,
                            "scanned_by": scanned_by,
                            "timestamp": datetime.datetime.now().isoformat(),
                        }
                    })
                except Exception:
                    pass
            self.set_header("Content-Type", "application/json")
            self.write(json_encode(result))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderBatchScanHandler(BaseHandler):
    """POST /api/work-orders/batch-scan — Batch start/finish items by prefix."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            prefix = body.get("prefix", "").strip()
            action = body.get("action", "").strip()
            user = self.get_current_user() or "shop"
            if not job_code or not prefix or not action:
                self.write(json_encode({"ok": False, "error": "Missing job_code, prefix, or action"}))
                return
            result = qr_scan_batch(SHOP_DRAWINGS_DIR, job_code, prefix, action, user)
            # ── Broadcast batch scan event via WebSocket ──
            if result.get("ok"):
                try:
                    LiveUpdateWebSocket.broadcast({
                        "type": "batch_scan",
                        "action": action,
                        "data": {
                            "job_code": job_code,
                            "prefix": prefix,
                            "scanned_by": user,
                            "count": result.get("processed", 0),
                            "timestamp": datetime.datetime.now().isoformat(),
                        }
                    })
                except Exception:
                    pass
            self.set_header("Content-Type", "application/json")
            self.write(json_encode(result))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderItemNotesHandler(BaseHandler):
    """POST /api/work-orders/item-notes — Add notes to a work order item."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            notes = body.get("notes", "").strip()

            if not job_code or not item_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or item_id"}))
                return

            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo is None or item is None:
                self.write(json_encode({"ok": False, "error": "Item not found"}))
                return

            item.notes = notes
            save_work_order(SHOP_DRAWINGS_DIR, wo)

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({"ok": True, "item": item.to_dict()}))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderEditHandler(BaseHandler):
    """POST /api/work-orders/edit — Edit work order fields (notes, priority, dates, etc.)."""
    required_roles = ["admin", "estimator"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            if not job_code or not wo_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or wo_id"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            # Editable fields
            editable = [
                "notes", "priority", "due_date", "delivery_date",
                "ship_to", "project_name", "customer_name",
                "machine_id", "operator",
            ]
            # Validate priority if provided
            if "priority" in body and body["priority"] not in ("urgent", "high", "normal", "low"):
                self.write(json_encode({"ok": False, "error": "Invalid priority. Use urgent/high/normal/low."}))
                return
            changes = {}
            for fld in editable:
                if fld in body:
                    old_val = getattr(wo, fld, "")
                    new_val = body[fld]
                    if old_val != new_val:
                        setattr(wo, fld, new_val)
                        changes[fld] = {"old": old_val, "new": new_val}

            if not changes:
                self.write(json_encode({"ok": True, "message": "No changes", "work_order": wo.to_dict()}))
                return

            save_work_order(SHOP_DRAWINGS_DIR, wo)
            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "changes": changes,
                "work_order": wo.to_dict(),
                "summary": wo.summary(),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderStatusHandler(BaseHandler):
    """POST /api/work-orders/status — Change work order status with pipeline validation.

    Status pipeline: queued -> in_progress -> qc_hold -> completed -> shipped
    Can't skip steps. Logs timestamps and calculates actual_hours.
    """
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            new_status = body.get("status", "").strip()
            user = body.get("user", self.get_current_user() or "system")

            if not job_code or not wo_id or not new_status:
                self.write(json_encode({"ok": False, "error": "Missing job_code, wo_id, or status"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            # Validate transition
            current = wo.status
            allowed = STATUS_FLOW.get(current, [])
            if new_status not in allowed:
                allowed_labels = [STATUS_LABELS.get(s, s) for s in allowed]
                self.write(json_encode({
                    "ok": False,
                    "error": f"Cannot transition from '{STATUS_LABELS.get(current, current)}' to '{STATUS_LABELS.get(new_status, new_status)}'. Allowed: {', '.join(allowed_labels) or 'none'}"
                }))
                return

            now = datetime.datetime.now().isoformat()
            old_status = wo.status
            wo.status = new_status

            # Status-specific side effects
            if new_status in (STATUS_IN_PROGRESS, STATUS_IN_FABRICATION):
                if not wo.start_time:
                    wo.start_time = now
            elif new_status == STATUS_QC_IN_PROCESS:
                # Check if all items have in-process QC done
                wo.qc_in_process_complete = all(
                    getattr(i, "qc_checklist", []) and all(
                        c.get("result") in ("pass", "n/a") for c in getattr(i, "qc_checklist", [])
                    )
                    for i in wo.items
                    if getattr(i, "item_category", "fabricated") == "fabricated"
                )
            elif new_status == STATUS_QC_FINAL:
                pass  # Will be set when all final QC is done
            elif new_status == STATUS_QC_APPROVED_WO:
                wo.qc_final_complete = True
            elif new_status == STATUS_NCR_HOLD:
                wo.notes = f"[NCR HOLD at {now}] " + wo.notes
            elif new_status == STATUS_READY_TO_SHIP:
                pass  # Ready for shipping crew
            elif new_status == STATUS_COMPLETE:
                wo.end_time = now
                # Calculate actual hours
                if wo.start_time:
                    try:
                        start = datetime.datetime.fromisoformat(wo.start_time.replace("Z", "+00:00"))
                        end = datetime.datetime.fromisoformat(now.replace("Z", "+00:00"))
                        wo.actual_hours = round((end - start).total_seconds() / 3600.0, 2)
                    except Exception:
                        pass
                # Check if ALL WOs for this project are completed — auto-advance to shipping
                try:
                    all_project_wos = list_work_orders(SHOP_DRAWINGS_DIR, job_code)
                    all_completed = all(
                        (w.get("status") in (STATUS_COMPLETE, STATUS_SHIPPED_WO, "complete", "shipped")
                         or w.get("work_order_id") == wo_id)
                        for w in all_project_wos
                    )
                    if all_completed:
                        _auto_advance_stage(job_code, "shipping")
                except Exception:
                    pass
            elif new_status == STATUS_QC_HOLD:
                wo.notes = f"[QC HOLD at {now}] " + wo.notes
            elif new_status == STATUS_SHIPPED_WO:
                # Check if all WOs for this project are shipped
                try:
                    all_project_wos = list_work_orders(SHOP_DRAWINGS_DIR, job_code)
                    all_shipped = all(
                        (w.get("status") in (STATUS_SHIPPED_WO, "shipped") or w.get("work_order_id") == wo_id)
                        for w in all_project_wos
                    )
                    if all_shipped:
                        _auto_advance_stage(job_code, "shipping")
                except Exception:
                    pass

            save_work_order(SHOP_DRAWINGS_DIR, wo)
            self._log("wo_status_change", "work_order", wo_id, {
                "job_code": job_code,
                "from": old_status,
                "to": new_status,
                "by": user,
            })

            # ── Email notification for WO status change ──
            try:
                send_notification("wo_status_change", context_data={
                    "job_code": job_code,
                    "wo_id": wo_id,
                    "from_status": STATUS_LABELS.get(old_status, old_status),
                    "to_status": STATUS_LABELS.get(new_status, new_status),
                    "changed_by": user,
                    "timestamp": now,
                    "subject": f"WO {wo_id} status: {STATUS_LABELS.get(new_status, new_status)}",
                })
            except Exception:
                pass

            # Broadcast via WebSocket
            try:
                LiveUpdateWebSocket.broadcast({
                    "type": "wo_status",
                    "action": "status_change",
                    "data": {
                        "job_code": job_code,
                        "wo_id": wo_id,
                        "from_status": old_status,
                        "to_status": new_status,
                        "timestamp": now,
                    }
                })
            except Exception:
                pass

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "work_order": wo.to_dict(),
                "summary": wo.summary(),
                "transition": {"from": old_status, "to": new_status},
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderTransitionHandler(BaseHandler):
    """POST /api/work-orders/transition — Transition a work order ITEM to a new status.

    Used by the global WO page for QC approve/reject and shipping status changes.
    """
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            new_status = body.get("new_status", "").strip()
            notes = body.get("notes", "")
            user = body.get("user", self.get_current_user() or "system")

            if not job_code or not item_id or not new_status:
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, or new_status"}))
                return

            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo is None or item is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Item not found"}))
                return

            old_status = item.status
            if not transition_item_status(item, new_status):
                self.set_status(400)
                self.write(json_encode({"ok": False, "error": f"Invalid status: '{new_status}'"}))
                return

            # ── BLOCK unqualified inspectors on critical QC transitions ──
            if new_status in ("qc_approved", "qc_rejected") and getattr(item, "is_critical", False):
                try:
                    from shop_drawings.qa_system import validate_inspector_for_scope
                    val = validate_inspector_for_scope(SHOP_DRAWINGS_DIR, user, "qc_hold_release")
                    if not val.get("ok"):
                        # Roll back the transition
                        transition_item_status(item, old_status)
                        required = val.get("required_certs", ["CWI", "SCWI"])
                        self.set_header("Content-Type", "application/json")
                        self.write(json_encode({
                            "ok": False,
                            "error": (
                                f"Inspector '{user}' is not qualified to {new_status.replace('_', ' ')} "
                                f"critical item '{item_id}'. "
                                f"Required certification: {', '.join(required)}. "
                                f"Reason: {val.get('error', 'missing or expired qualification')}"
                            ),
                            "blocked": True,
                            "required_certs": required,
                        }))
                        return
                except ImportError:
                    pass  # If qa_system unavailable, allow transition

            # Set QC fields for QC transitions
            now_ts = datetime.datetime.now().isoformat()
            if new_status == "qc_approved":
                item.qc_status = "passed"
                item.qc_inspector = user
                item.qc_inspected_at = now_ts
                item.qc_final_status = "passed"
                item.qc_final_inspector = user
                item.qc_final_at = now_ts
                if notes:
                    item.qc_notes = notes
                add_audit_entry(item, user, "qc_approved", notes or "QC approved")
            elif new_status == "qc_rejected":
                item.qc_status = "failed"
                item.qc_inspector = user
                item.qc_inspected_at = now_ts
                item.qc_final_status = "failed"
                item.qc_final_inspector = user
                item.qc_final_at = now_ts
                if notes:
                    item.qc_notes = notes
                add_audit_entry(item, user, "qc_rejected", notes or "QC rejected")
                # Auto-create NCR on rejection
                severity = "critical" if getattr(item, "is_critical", False) else "minor"
                ncr = create_ncr(wo.work_order_id, item_id,
                                 notes or "QC inspection rejected",
                                 user, severity=severity)
                item.ncr_id = ncr["ncr_id"]
                safe_jc = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
                ncr_dir = os.path.join(SHOP_DRAWINGS_DIR, safe_jc, "ncrs")
                os.makedirs(ncr_dir, exist_ok=True)
                with open(os.path.join(ncr_dir, f"{ncr['ncr_id']}.json"), "w") as f:
                    json.dump(ncr, f, indent=2)
            elif new_status == "qc_pending":
                item.qc_status = "pending"
                add_audit_entry(item, user, "qc_reset", "QC status reset to pending")
            elif new_status in ("shipped", "delivered"):
                if new_status == "shipped":
                    item.loading_status = "shipped"
                elif new_status == "delivered":
                    item.loading_status = "delivered"
                add_audit_entry(item, user, f"loading_{new_status}", notes or "")
            else:
                add_audit_entry(item, user, f"status_{new_status}",
                                notes or f"Transitioned to {new_status}")

            if notes and new_status not in ("qc_approved", "qc_rejected"):
                item.notes = (item.notes + "\n" + notes).strip()

            save_work_order(SHOP_DRAWINGS_DIR, wo)
            self._log("item_transition", "work_order_item", item_id, {
                "job_code": job_code,
                "from": old_status,
                "to": new_status,
                "by": user,
            })

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "item": item.to_dict(),
                "transition": {"from": old_status, "to": new_status},
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderAssignHandler(BaseHandler):
    """POST /api/work-orders/assign — Assign a machine and/or operator to a work order."""
    required_roles = ["admin", "estimator"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            machine_id = body.get("machine_id", "").strip()
            operator = body.get("operator", "").strip()

            if not job_code or not wo_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or wo_id"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            changes = {}
            if machine_id and machine_id != wo.machine_id:
                changes["machine_id"] = {"old": wo.machine_id, "new": machine_id}
                wo.machine_id = machine_id
            if operator and operator != wo.operator:
                changes["operator"] = {"old": wo.operator, "new": operator}
                wo.operator = operator

            if not changes:
                self.write(json_encode({"ok": True, "message": "No changes"}))
                return

            save_work_order(SHOP_DRAWINGS_DIR, wo)
            self._log("wo_assigned", "work_order", wo_id, {
                "job_code": job_code,
                "changes": changes,
            })

            # Broadcast assignment
            try:
                LiveUpdateWebSocket.broadcast({
                    "type": "wo_assigned",
                    "data": {
                        "job_code": job_code,
                        "wo_id": wo_id,
                        "machine_id": wo.machine_id,
                        "operator": wo.operator,
                        "timestamp": datetime.datetime.now().isoformat(),
                    }
                })
            except Exception:
                pass

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "changes": changes,
                "work_order": wo.to_dict(),
                "summary": wo.summary(),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderDeleteHandler(BaseHandler):
    """POST /api/work-orders/delete — Delete a work order."""
    required_roles = ["admin"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            if not job_code or not wo_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or wo_id"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            # Don't allow deleting in-progress work orders
            if wo.status == STATUS_IN_PROGRESS:
                self.write(json_encode({"ok": False, "error": "Cannot delete an in-progress work order. Put it on hold first."}))
                return

            deleted = delete_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            self._log("deleted_work_order", "work_order", wo_id, {"job_code": job_code})
            if not deleted:
                self.set_status(500)
                self.write(json_encode({"ok": False, "error": "Failed to delete work order file"}))
                return

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "message": f"Work order {wo_id} deleted",
                "deleted_wo_id": wo_id,
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderItemEditHandler(BaseHandler):
    """POST /api/work-orders/item-edit — Edit a single work order item."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            if not job_code or not item_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or item_id"}))
                return

            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo is None or item is None:
                self.write(json_encode({"ok": False, "error": "Item not found"}))
                return

            # Editable item fields
            editable = [
                "assigned_to", "machine", "notes", "description",
                "quantity", "truck_number",
                # AISC traceability fields
                "heat_number", "mtr_link", "coil_tag",
                # Welding / bolting documentation
                "wps_reference", "calibration_id",
            ]
            changes = {}
            user = body.get("user", self.get_current_user() or "system")
            for fld in editable:
                if fld in body:
                    old_val = getattr(item, fld, "")
                    new_val = body[fld]
                    if old_val != new_val:
                        setattr(item, fld, new_val)
                        changes[fld] = {"old": old_val, "new": new_val}

            # Handle welder_ids as a list append/replace
            if "welder_ids" in body:
                new_ids = body["welder_ids"]
                if isinstance(new_ids, list):
                    old_ids = list(getattr(item, "welder_ids", []))
                    item.welder_ids = new_ids
                    if old_ids != new_ids:
                        changes["welder_ids"] = {"old": old_ids, "new": new_ids}

            if not changes:
                self.write(json_encode({"ok": True, "message": "No changes", "item": item.to_dict()}))
                return

            # Add audit entry for traceability
            if HAS_SHOP_DRAWINGS:
                for fld, chg in changes.items():
                    add_audit_entry(item, user, f"edit_{fld}",
                                    f"Changed {fld}", str(chg["old"]), str(chg["new"]))

            save_work_order(SHOP_DRAWINGS_DIR, wo)
            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "changes": changes,
                "item": item.to_dict(),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderChecklistHandler(BaseHandler):
    """GET/POST /api/work-orders/checklist — Fab step checklist per item."""
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        job_code = self.get_argument("job_code", "")
        item_id = self.get_argument("item_id", "")
        if not job_code or not item_id:
            self.write(json_encode({"ok": False, "error": "Missing job_code or item_id"}))
            return
        result = init_fab_checklist(SHOP_DRAWINGS_DIR, job_code, item_id)
        self.set_header("Content-Type", "application/json")
        self.write(json_encode(result))

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            step_num = int(body.get("step_num", 0))
            user = self.get_current_user() or "shop"
            if not job_code or not item_id or not step_num:
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, or step_num"}))
                return
            result = check_fab_step(SHOP_DRAWINGS_DIR, job_code, item_id, step_num, user)
            self.set_header("Content-Type", "application/json")
            self.write(json_encode(result))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderQCHandler(BaseHandler):
    """POST /api/work-orders/qc — QC inspection pass/fail for a work order item.

    Enhanced to support:
    - Per-item QC with is_critical flag enforcement
    - Auto-NCR creation on QC failure
    - QC final status tracking
    - Audit trail entries
    """
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            qc_status = body.get("qc_status", "").strip()
            inspector = body.get("inspector", self.get_current_user() or "qc")
            qc_notes = body.get("qc_notes", "").strip()
            is_final = body.get("is_final", False)  # True = final QC, False = in-process

            if not job_code or not item_id or not qc_status:
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, or qc_status"}))
                return

            # ── Inspector Qualification Validation ──
            try:
                from shop_drawings.qa_system import validate_inspector_for_scope
                val = validate_inspector_for_scope(SHOP_DRAWINGS_DIR, inspector, "qc_hold_release")
            except Exception:
                val = {"ok": True, "reason": "validation_unavailable"}

            # ── BLOCK unqualified inspectors on critical items ──
            wo_pre, item_pre = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo_pre and item_pre and getattr(item_pre, "is_critical", False):
                if not val.get("ok"):
                    required = val.get("required_certs", ["CWI", "SCWI"])
                    self.set_header("Content-Type", "application/json")
                    self.write(json_encode({
                        "ok": False,
                        "error": (
                            f"Inspector '{inspector}' is not qualified for QC on critical item '{item_id}'. "
                            f"Required certification: {', '.join(required)}. "
                            f"Reason: {val.get('error', 'missing or expired qualification')}"
                        ),
                        "blocked": True,
                        "required_certs": required,
                    }))
                    return

            result = qc_inspect_item(SHOP_DRAWINGS_DIR, job_code, item_id,
                                      inspector, qc_status, qc_notes)

            if result.get("ok"):
                result["inspector_qualified"] = val.get("ok", False)
                if not val.get("ok") and val.get("error"):
                    result["inspector_warning"] = val.get("error", "")

                # ── Enhanced: Set final QC fields if this is a final inspection ──
                wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
                if wo and item:
                    if is_final:
                        item.qc_final_status = qc_status
                        item.qc_final_inspector = inspector
                        item.qc_final_at = datetime.datetime.now().isoformat()

                    # Add audit trail entry
                    add_audit_entry(item, inspector,
                                    f"qc_{'final' if is_final else 'inprocess'}_{qc_status}",
                                    qc_notes)

                    # ── Auto-NCR on failure ──
                    ncr_data = None
                    if qc_status == "failed":
                        severity = "critical" if getattr(item, "is_critical", False) else "minor"
                        ncr_data = create_ncr(wo.work_order_id, item_id,
                                              qc_notes or f"QC {('final' if is_final else 'in-process')} inspection failed",
                                              inspector, severity=severity)
                        item.ncr_id = ncr_data["ncr_id"]
                        # Save NCR to disk
                        ncr_dir = os.path.join(SHOP_DRAWINGS_DIR, re.sub(r"[^a-zA-Z0-9_-]", "_", job_code), "ncrs")
                        os.makedirs(ncr_dir, exist_ok=True)
                        ncr_path = os.path.join(ncr_dir, f"{ncr_data['ncr_id']}.json")
                        with open(ncr_path, "w") as f:
                            json.dump(ncr_data, f, indent=2)
                        result["ncr"] = ncr_data

                        # If critical item failed, suggest WO status change to NCR hold
                        if getattr(item, "is_critical", False):
                            result["critical_failure"] = True
                            result["suggested_wo_status"] = STATUS_NCR_HOLD
                            # ── Notify on critical QC failure ──
                            try:
                                send_notification("qc_critical_fail", context_data={
                                    "job_code": job_code,
                                    "wo_id": wo.work_order_id,
                                    "item_id": item_id,
                                    "component_type": getattr(item, "component_type", ""),
                                    "ship_mark": getattr(item, "ship_mark", ""),
                                    "inspector": inspector,
                                    "ncr_id": ncr_data.get("ncr_id", "") if ncr_data else "",
                                    "severity": severity,
                                    "is_final": is_final,
                                    "subject": f"CRITICAL QC Fail: {getattr(item, 'ship_mark', item_id)} on WO {wo.work_order_id}",
                                })
                            except Exception:
                                pass

                    # ── Check overall WO QC status ──
                    suggested = check_wo_qc_status(wo)
                    result["wo_qc_suggestion"] = suggested

                    save_work_order(SHOP_DRAWINGS_DIR, wo)

            if result.get("ok"):
                self._log("qc_inspection", "work_order_item", item_id, {
                    "job_code": job_code, "qc_status": qc_status,
                    "inspector": inspector, "is_final": is_final,
                })

            self.set_header("Content-Type", "application/json")
            self.write(json_encode(result))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderQCPhotoHandler(BaseHandler):
    """POST /api/work-orders/qc-photo — Upload a QC inspection photo."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            job_code = self.get_argument("job_code", "")
            item_id = self.get_argument("item_id", "")
            if not job_code or not item_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or item_id"}))
                return

            # Get uploaded file
            if "photo" not in self.request.files:
                self.write(json_encode({"ok": False, "error": "No photo uploaded"}))
                return

            photo = self.request.files["photo"][0]
            filename = photo["filename"]

            # SEC-007: Sanitize job_code to prevent path traversal
            safe_job = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            # Save photo to qc_photos directory
            photo_dir = os.path.join(SHOP_DRAWINGS_DIR, safe_job, "qc_photos")
            os.makedirs(photo_dir, exist_ok=True)

            # Generate unique filename
            safe_item = re.sub(r"[^A-Za-z0-9_-]", "_", item_id)
            ext = os.path.splitext(filename)[1].lower() or ".jpg"
            # SEC-007: Whitelist allowed image extensions
            allowed_extensions = {".jpg", ".jpeg", ".png", ".gif", ".webp"}
            if ext not in allowed_extensions:
                self.write(json_encode({"ok": False, "error": f"File type '{ext}' not allowed. Use jpg, png, gif, or webp."}))
                return
            photo_filename = f"{safe_item}_{int(time.time())}{ext}"
            photo_path = os.path.join(photo_dir, photo_filename)

            with open(photo_path, "wb") as f:
                f.write(photo["body"])

            # Update work order item
            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo and item:
                if not hasattr(item, 'qc_photos') or not isinstance(item.qc_photos, list):
                    item.qc_photos = []
                item.qc_photos.append(photo_filename)
                save_work_order(SHOP_DRAWINGS_DIR, wo)

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "filename": photo_filename,
                "message": f"Photo uploaded for {item_id}",
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderQCPhotoServeHandler(BaseHandler):
    """GET /api/work-orders/qc-photo/file — Serve a QC photo."""
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        job_code = self.get_argument("job_code", "")
        filename = self.get_argument("filename", "")
        if not job_code or not filename:
            self.set_status(400)
            return
        safe_fn = os.path.basename(filename)
        photo_path = os.path.join(SHOP_DRAWINGS_DIR, job_code, "qc_photos", safe_fn)
        if not os.path.exists(photo_path):
            self.set_status(404)
            return
        ext = os.path.splitext(safe_fn)[1].lower()
        ct = {"jpg": "image/jpeg", ".jpeg": "image/jpeg", ".png": "image/png"}.get(ext, "image/jpeg")
        self.set_header("Content-Type", ct)
        with open(photo_path, "rb") as f:
            self.write(f.read())


class WorkOrderQCChecklistHandler(BaseHandler):
    """GET/POST /api/work-orders/qc-checklist — Per-item QC checklist operations.

    GET: Returns the QC checklist for a specific WO item
    POST: Updates a QC checklist item (pass/fail/n_a for a specific check)
    """
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        try:
            job_code = self.get_argument("job_code", "")
            item_id = self.get_argument("item_id", "")
            if not job_code or not item_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or item_id"}))
                return
            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo is None or item is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Item not found"}))
                return
            checklist = getattr(item, "qc_checklist", [])
            # If checklist empty, initialize from template
            if not checklist:
                ctype = (item.component_type or "").lower()
                checklist = get_qc_checklist_template(ctype)
                item.qc_checklist = checklist
                save_work_order(SHOP_DRAWINGS_DIR, wo)
            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "item_id": item_id,
                "component_type": item.component_type,
                "is_critical": getattr(item, "is_critical", False),
                "checklist": checklist,
                "qc_final_status": getattr(item, "qc_final_status", ""),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            check_id = body.get("check_id", "").strip()
            result_val = body.get("result", "").strip()  # "pass", "fail", "n/a"
            inspector = body.get("inspector", self.get_current_user() or "qc")
            notes = body.get("notes", "")
            photo = body.get("photo", "")

            if not job_code or not item_id or not check_id or not result_val:
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, check_id, or result"}))
                return
            if result_val not in ("pass", "fail", "n/a"):
                self.write(json_encode({"ok": False, "error": "result must be 'pass', 'fail', or 'n/a'"}))
                return

            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo is None or item is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Item not found"}))
                return

            # ── BLOCK unqualified inspectors on critical component checklists ──
            if getattr(item, "is_critical", False):
                try:
                    from shop_drawings.qa_system import validate_inspector_for_scope
                    # Determine scope from check_id prefix
                    if "weld" in check_id.lower():
                        scope = "visual_weld"
                    elif "dimension" in check_id.lower() or "measure" in check_id.lower():
                        scope = "dimensional"
                    else:
                        scope = "qc_hold_release"
                    val = validate_inspector_for_scope(SHOP_DRAWINGS_DIR, inspector, scope)
                    if not val.get("ok"):
                        required = val.get("required_certs", ["CWI", "SCWI"])
                        self.set_header("Content-Type", "application/json")
                        self.write(json_encode({
                            "ok": False,
                            "error": (
                                f"Inspector '{inspector}' is not qualified for '{scope}' checks "
                                f"on critical item '{item_id}'. "
                                f"Required certification: {', '.join(required)}. "
                                f"Reason: {val.get('error', 'missing or expired qualification')}"
                            ),
                            "blocked": True,
                            "required_certs": required,
                        }))
                        return
                except ImportError:
                    pass  # If qa_system unavailable, allow

            checklist = getattr(item, "qc_checklist", [])
            if not checklist:
                ctype = (item.component_type or "").lower()
                checklist = get_qc_checklist_template(ctype)
                item.qc_checklist = checklist

            # Find and update the check
            found = False
            for check in item.qc_checklist:
                if check.get("id") == check_id:
                    check["result"] = result_val
                    check["inspector"] = inspector
                    check["timestamp"] = datetime.datetime.now().isoformat()
                    if notes:
                        check["notes"] = notes
                    if photo:
                        check["photo"] = photo
                    found = True
                    break

            if not found:
                self.write(json_encode({"ok": False, "error": f"Check '{check_id}' not found in checklist"}))
                return

            # Add audit entry
            add_audit_entry(item, inspector, f"qc_check_{result_val}",
                            f"QC check '{check_id}': {result_val}", "", result_val)

            # Check if all checklist items are done
            all_done = all(c.get("result") in ("pass", "n/a") for c in item.qc_checklist)
            any_failed = any(c.get("result") == "fail" for c in item.qc_checklist)

            save_work_order(SHOP_DRAWINGS_DIR, wo)

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "check_id": check_id,
                "result": result_val,
                "checklist": item.qc_checklist,
                "all_passed": all_done and not any_failed,
                "any_failed": any_failed,
                "is_critical": getattr(item, "is_critical", False),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderMaterialReceiptHandler(BaseHandler):
    """POST /api/work-orders/material-receipt — Record material receipt inspection.

    Covers:
    1. Material receipt inspection (verify heat number matches MTR)
    2. Lost ID procedure (when heat number is lost, issue new internal ID)
    """
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            item_id = body.get("item_id", "").strip()
            action = body.get("action", "").strip()  # "inspect" or "lost_id"
            inspector = body.get("inspector", self.get_current_user() or "receiving")

            if not job_code or not item_id or not action:
                self.set_header("Content-Type", "application/json")
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, or action"}))
                return

            if action not in ("inspect", "lost_id"):
                self.set_header("Content-Type", "application/json")
                self.write(json_encode({"ok": False, "error": "action must be 'inspect' or 'lost_id'"}))
                return

            wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
            if wo is None or item is None:
                self.set_status(404)
                self.set_header("Content-Type", "application/json")
                self.write(json_encode({"ok": False, "error": "Work order item not found"}))
                return

            now_ts = datetime.datetime.now().isoformat()

            if action == "inspect":
                heat_number = body.get("heat_number", "").strip()
                mtr_link = body.get("mtr_link", "").strip()
                coil_tag = body.get("coil_tag", "").strip()
                condition = body.get("condition", "good").strip()
                notes = body.get("notes", "").strip()

                if condition not in ("good", "damaged", "rejected"):
                    self.set_header("Content-Type", "application/json")
                    self.write(json_encode({"ok": False, "error": "condition must be 'good', 'damaged', or 'rejected'"}))
                    return

                # Update item fields
                if heat_number:
                    item.heat_number = heat_number
                if mtr_link:
                    item.mtr_link = mtr_link
                if coil_tag:
                    item.coil_tag = coil_tag
                item.material_condition = condition
                item.material_inspected_by = inspector
                item.material_inspected_at = now_ts

                # Add audit trail
                details = f"Material receipt inspection: condition={condition}"
                if heat_number:
                    details += f", heat={heat_number}"
                if coil_tag:
                    details += f", coil_tag={coil_tag}"
                if notes:
                    details += f", notes: {notes}"
                add_audit_entry(item, inspector, "material_receipt_inspect", details)

                if condition == "rejected":
                    item.material_condition = "rejected"
                    add_audit_entry(item, inspector, "material_rejected",
                                    notes or "Material rejected at receiving inspection")

                save_work_order(SHOP_DRAWINGS_DIR, wo)

                self._log("material_receipt", "work_order_item", item_id, {
                    "job_code": job_code, "action": "inspect",
                    "condition": condition, "inspector": inspector,
                })

                self.set_header("Content-Type", "application/json")
                self.write(json_encode({
                    "ok": True,
                    "action": "inspect",
                    "item_id": item_id,
                    "condition": condition,
                    "heat_number": heat_number,
                    "mtr_link": mtr_link,
                    "coil_tag": coil_tag,
                    "inspector": inspector,
                    "inspected_at": now_ts,
                }))

            elif action == "lost_id":
                original_heat = body.get("original_heat_number", "").strip()
                new_internal_id = body.get("new_internal_id", "").strip()
                reason = body.get("reason", "").strip()
                notes = body.get("notes", "").strip()

                if not reason:
                    self.set_header("Content-Type", "application/json")
                    self.write(json_encode({"ok": False, "error": "reason is required for lost ID procedure"}))
                    return

                # Auto-generate internal ID if not provided
                if not new_internal_id:
                    date_str = datetime.datetime.now().strftime("%Y%m%d")
                    # Generate sequence number based on existing LIDs in this WO
                    seq = 1
                    for it in wo.items:
                        lid = getattr(it, "lost_id_number", "")
                        if lid and lid.startswith(f"LID-{date_str}-"):
                            try:
                                s = int(lid.split("-")[-1])
                                if s >= seq:
                                    seq = s + 1
                            except ValueError:
                                pass
                    new_internal_id = f"LID-{date_str}-{seq:03d}"

                # Record original heat number if known
                if original_heat:
                    item.original_heat_number = original_heat
                item.heat_number = new_internal_id
                item.lost_id_number = new_internal_id
                item.lost_id_reason = reason
                item.lost_id_issued_by = inspector
                item.lost_id_issued_at = now_ts
                item.lost_id_flagged = True

                # Audit trail
                details = f"Lost ID procedure: new ID={new_internal_id}, reason={reason}"
                if original_heat:
                    details += f", original heat={original_heat}"
                if notes:
                    details += f", notes: {notes}"
                add_audit_entry(item, inspector, "lost_id_issued", details,
                                original_heat or "(unknown)", new_internal_id)

                save_work_order(SHOP_DRAWINGS_DIR, wo)

                self._log("material_receipt", "work_order_item", item_id, {
                    "job_code": job_code, "action": "lost_id",
                    "new_internal_id": new_internal_id, "inspector": inspector,
                })

                self.set_header("Content-Type", "application/json")
                self.write(json_encode({
                    "ok": True,
                    "action": "lost_id",
                    "item_id": item_id,
                    "new_internal_id": new_internal_id,
                    "original_heat_number": original_heat,
                    "reason": reason,
                    "inspector": inspector,
                    "issued_at": now_ts,
                    "flagged": True,
                }))

        except Exception as e:
            self.set_status(500)
            self.set_header("Content-Type", "application/json")
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderNCRHandler(BaseHandler):
    """GET/POST /api/work-orders/ncr — NCR management.

    GET: List NCRs for a job or specific WO
    POST: Create or update an NCR
    """
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        try:
            job_code = self.get_argument("job_code", "")
            wo_id = self.get_argument("wo_id", "")
            ncr_id = self.get_argument("ncr_id", "")
            if not job_code:
                self.write(json_encode({"ok": False, "error": "Missing job_code"}))
                return

            safe_jc = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            ncr_dir = os.path.join(SHOP_DRAWINGS_DIR, safe_jc, "ncrs")
            ncrs = []

            if ncr_id:
                # Return a specific NCR
                ncr_path = os.path.join(ncr_dir, f"{ncr_id}.json")
                if os.path.isfile(ncr_path):
                    with open(ncr_path) as f:
                        ncrs = [json.load(f)]
            elif os.path.isdir(ncr_dir):
                for fname in sorted(os.listdir(ncr_dir), reverse=True):
                    if not fname.endswith(".json"):
                        continue
                    try:
                        with open(os.path.join(ncr_dir, fname)) as f:
                            ncr = json.load(f)
                        if wo_id and ncr.get("wo_id") != wo_id:
                            continue
                        ncrs.append(ncr)
                    except Exception:
                        continue

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "ncrs": ncrs,
                "total": len(ncrs),
                "open": sum(1 for n in ncrs if n.get("status") in ("open", "in_review")),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            action = body.get("action", "create").strip()

            if not job_code:
                self.write(json_encode({"ok": False, "error": "Missing job_code"}))
                return

            safe_jc = re.sub(r"[^a-zA-Z0-9_-]", "_", job_code)
            ncr_dir = os.path.join(SHOP_DRAWINGS_DIR, safe_jc, "ncrs")
            os.makedirs(ncr_dir, exist_ok=True)

            if action == "create":
                wo_id = body.get("wo_id", "")
                item_id = body.get("item_id", "")
                description = body.get("description", "")
                inspector = body.get("inspector", self.get_current_user() or "qc")
                severity = body.get("severity", "minor")
                photos = body.get("photos", [])

                ncr = create_ncr(wo_id, item_id, description, inspector, photos, severity)

                # Link to WO item
                if item_id and wo_id:
                    wo, item = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
                    if wo and item:
                        item.ncr_id = ncr["ncr_id"]
                        item.qc_status = "failed"
                        add_audit_entry(item, inspector, "ncr_created",
                                        f"NCR {ncr['ncr_id']} created: {description}")
                        save_work_order(SHOP_DRAWINGS_DIR, wo)

                ncr_path = os.path.join(ncr_dir, f"{ncr['ncr_id']}.json")
                with open(ncr_path, "w") as f:
                    json.dump(ncr, f, indent=2)

                self._log("ncr_created", "ncr", ncr["ncr_id"], {
                    "job_code": job_code, "wo_id": wo_id,
                    "item_id": item_id, "severity": severity,
                })

                # ── Email notification for NCR creation ──
                try:
                    send_notification("ncr_created", context_data={
                        "job_code": job_code,
                        "wo_id": wo_id,
                        "item_id": item_id,
                        "ncr_id": ncr["ncr_id"],
                        "severity": severity,
                        "description": description[:200],
                        "inspector": inspector,
                        "subject": f"NCR {ncr['ncr_id']} ({severity.upper()}) opened on {job_code}",
                    })
                except Exception:
                    pass

                self.set_header("Content-Type", "application/json")
                self.write(json_encode({"ok": True, "ncr": ncr}))

            elif action == "update":
                ncr_id = body.get("ncr_id", "").strip()
                if not ncr_id:
                    self.write(json_encode({"ok": False, "error": "Missing ncr_id"}))
                    return

                ncr_path = os.path.join(ncr_dir, f"{ncr_id}.json")
                if not os.path.isfile(ncr_path):
                    self.set_status(404)
                    self.write(json_encode({"ok": False, "error": "NCR not found"}))
                    return

                with open(ncr_path) as f:
                    ncr = json.load(f)

                # Updatable fields
                for fld in ["root_cause", "corrective_action", "disposition",
                            "disposition_by", "status"]:
                    if fld in body:
                        ncr[fld] = body[fld]

                now = datetime.datetime.now().isoformat()
                user = body.get("user", self.get_current_user() or "system")

                if body.get("disposition"):
                    ncr["disposition_by"] = user
                    ncr["disposition_at"] = now
                if body.get("status") == "resolved":
                    ncr["resolved_by"] = user
                    ncr["resolved_at"] = now

                with open(ncr_path, "w") as f:
                    json.dump(ncr, f, indent=2)

                self._log("ncr_updated", "ncr", ncr_id, {
                    "job_code": job_code, "status": ncr.get("status"),
                    "by": user,
                })

                self.set_header("Content-Type", "application/json")
                self.write(json_encode({"ok": True, "ncr": ncr}))
            else:
                self.write(json_encode({"ok": False, "error": f"Unknown action: {action}"}))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderAuditLogHandler(BaseHandler):
    """GET /api/work-orders/audit-log — Retrieve audit trail for a WO or item.

    Returns immutable audit log entries with user, action, timestamp, details.
    """
    required_roles = ["admin", "estimator"]

    def get(self):
        try:
            job_code = self.get_argument("job_code", "")
            wo_id = self.get_argument("wo_id", "")
            item_id = self.get_argument("item_id", "")

            if not job_code or not wo_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or wo_id"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            audit_entries = []
            for item in wo.items:
                if item_id and item.item_id != item_id:
                    continue
                item_log = getattr(item, "audit_log", [])
                for entry in item_log:
                    entry_copy = dict(entry)
                    entry_copy["item_id"] = item.item_id
                    entry_copy["ship_mark"] = item.ship_mark
                    entry_copy["component_type"] = item.component_type
                    audit_entries.append(entry_copy)

            # Sort by timestamp descending
            audit_entries.sort(key=lambda x: x.get("timestamp", ""), reverse=True)

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "wo_id": wo_id,
                "entries": audit_entries,
                "total": len(audit_entries),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderTraceabilityHandler(BaseHandler):
    """GET/POST /api/work-orders/traceability — Heat number / MTR traceability.

    GET: Get traceability info for all items in a WO
    POST: Bulk-update heat numbers and MTR links for items
    """
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        try:
            job_code = self.get_argument("job_code", "")
            wo_id = self.get_argument("wo_id", "")
            if not job_code or not wo_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or wo_id"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            items = []
            for item in wo.items:
                items.append({
                    "item_id": item.item_id,
                    "ship_mark": item.ship_mark,
                    "component_type": item.component_type,
                    "heat_number": getattr(item, "heat_number", ""),
                    "mtr_link": getattr(item, "mtr_link", ""),
                    "coil_tag": getattr(item, "coil_tag", ""),
                    "is_critical": getattr(item, "is_critical", False),
                    "welder_ids": getattr(item, "welder_ids", []),
                    "wps_reference": getattr(item, "wps_reference", ""),
                    "calibration_id": getattr(item, "calibration_id", ""),
                })

            traced = sum(1 for i in items if i["heat_number"])
            total_fab = sum(1 for i in items if i["component_type"] not in ("trim",))

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "wo_id": wo_id,
                "items": items,
                "traced": traced,
                "total": total_fab,
                "pct_traced": round(100 * traced / max(total_fab, 1), 1),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            updates = body.get("updates", [])  # [{item_id, heat_number, mtr_link, coil_tag}]
            user = body.get("user", self.get_current_user() or "system")

            if not job_code or not wo_id or not updates:
                self.write(json_encode({"ok": False, "error": "Missing job_code, wo_id, or updates"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            item_map = {i.item_id: i for i in wo.items}
            results = []
            for upd in updates:
                iid = upd.get("item_id", "")
                item = item_map.get(iid)
                if not item:
                    results.append({"item_id": iid, "ok": False, "error": "Item not found"})
                    continue
                changes = []
                for fld in ("heat_number", "mtr_link", "coil_tag"):
                    if fld in upd:
                        old = getattr(item, fld, "")
                        new = upd[fld]
                        if old != new:
                            setattr(item, fld, new)
                            changes.append(fld)
                            add_audit_entry(item, user, f"set_{fld}",
                                            f"Set {fld}", old, new)
                results.append({"item_id": iid, "ok": True, "changed": changes})

            save_work_order(SHOP_DRAWINGS_DIR, wo)

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "results": results,
                "updated": sum(1 for r in results if r.get("ok")),
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderRevisionHandler(BaseHandler):
    """POST /api/work-orders/revision — Create a new revision of a work order.

    Creates a copy of the current WO with incremented revision_number,
    links to parent, and records the reason for change.
    """
    required_roles = ["admin", "estimator"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            wo_id = body.get("wo_id", "").strip()
            reason = body.get("reason", "").strip()
            user = body.get("user", self.get_current_user() or "system")

            if not job_code or not wo_id or not reason:
                self.write(json_encode({"ok": False, "error": "Missing job_code, wo_id, or reason"}))
                return

            wo = load_work_order(SHOP_DRAWINGS_DIR, job_code, wo_id)
            if wo is None:
                self.set_status(404)
                self.write(json_encode({"ok": False, "error": "Work order not found"}))
                return

            now = datetime.datetime.now().isoformat()
            old_rev = wo.revision_number

            # Create new WO as a copy
            import copy
            new_wo = copy.deepcopy(wo)
            new_wo.work_order_id = f"WO-{job_code}-{wo.revision}-{uuid.uuid4().hex[:6].upper()}"
            new_wo.revision_number = old_rev + 1
            new_wo.revision_reason = reason
            new_wo.parent_wo_id = wo_id
            new_wo.created_at = now
            new_wo.created_by = user
            new_wo.status = STATUS_QUEUED
            new_wo.approved_at = ""
            new_wo.approved_by = ""
            new_wo.start_time = ""
            new_wo.end_time = ""
            new_wo.actual_hours = 0.0

            # Record in revision history
            rev_entry = {
                "revision": old_rev + 1,
                "wo_id": new_wo.work_order_id,
                "reason": reason,
                "created_at": now,
                "created_by": user,
                "parent_wo_id": wo_id,
            }
            new_wo.revision_history = list(wo.revision_history or [])
            new_wo.revision_history.append(rev_entry)

            # Update item IDs to reflect new WO
            for item in new_wo.items:
                old_item_id = item.item_id
                item.item_id = item.item_id.replace(wo_id, new_wo.work_order_id)
                # Reset fabrication status
                item.status = STATUS_QUEUED
                item.started_by = ""
                item.started_at = ""
                item.finished_by = ""
                item.finished_at = ""
                item.duration_minutes = 0.0
                item.qc_status = "pending"
                item.qc_final_status = ""
                item.ncr_id = ""
                item.audit_log = []
                add_audit_entry(item, user, "revision_created",
                                f"Revision {old_rev + 1} from {wo_id}: {reason}")

            save_work_order(SHOP_DRAWINGS_DIR, new_wo)

            # Mark old WO as superseded
            wo.notes = f"[SUPERSEDED by Rev {old_rev + 1} at {now}] " + wo.notes
            save_work_order(SHOP_DRAWINGS_DIR, wo)

            self._log("wo_revision", "work_order", new_wo.work_order_id, {
                "job_code": job_code, "from_rev": old_rev,
                "to_rev": old_rev + 1, "reason": reason, "by": user,
            })

            # ── Email notification for WO revision ──
            try:
                send_notification("wo_revision", context_data={
                    "job_code": job_code,
                    "old_wo_id": wo_id,
                    "new_wo_id": new_wo.work_order_id,
                    "from_rev": old_rev,
                    "to_rev": old_rev + 1,
                    "reason": reason,
                    "created_by": user,
                    "subject": f"WO Revision {old_rev + 1} created for {job_code}: {reason[:80]}",
                })
            except Exception:
                pass

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "new_wo": new_wo.summary(),
                "revision_number": new_wo.revision_number,
                "parent_wo_id": wo_id,
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderLaborReportHandler(BaseHandler):
    """GET /api/work-orders/labor-report — Aggregated fabrication labor data.

    Returns actual vs estimated hours, per-operator efficiency, per-machine utilization,
    and per-component-type averages across all work orders for a job or all jobs.
    """
    required_roles = ["admin", "estimator", "project_manager", "general_manager"]

    def get(self):
        try:
            job_code = self.get_argument("job_code", "")
            from shop_drawings.work_orders import list_all_work_orders, load_work_order

            # Gather WOs — single job or all
            wo_summaries = []
            if job_code:
                wo_summaries = list_work_orders(SHOP_DRAWINGS_DIR, job_code)
            else:
                wo_summaries = list_all_work_orders(SHOP_DRAWINGS_DIR)

            total_estimated = 0.0
            total_actual = 0.0
            operator_stats = {}   # operator -> {items, total_minutes, components}
            machine_stats = {}    # machine -> {items, total_minutes}
            component_stats = {}  # component_type -> {count, total_est, total_actual, total_minutes}
            wo_count = 0
            completed_count = 0

            for ws in wo_summaries:
                jc = ws.get("job_code", job_code)
                wid = ws.get("work_order_id", "")
                if not jc or not wid:
                    continue
                wo = load_work_order(SHOP_DRAWINGS_DIR, jc, wid)
                if wo is None:
                    continue
                wo_count += 1
                if wo.status in ("complete", "completed", "shipped"):
                    completed_count += 1
                total_estimated += wo.estimated_hours or 0
                total_actual += wo.actual_hours or 0

                for item in wo.items:
                    ctype = (item.component_type or "other").lower()
                    dur = getattr(item, "duration_minutes", 0) or 0
                    est_min = getattr(item, "estimated_minutes", 0) or 0
                    est_h = est_min / 60.0 if est_min else 0
                    act_h = dur / 60.0 if dur else 0

                    # Component stats
                    if ctype not in component_stats:
                        component_stats[ctype] = {"count": 0, "total_est_hours": 0, "total_actual_hours": 0, "total_minutes": 0}
                    component_stats[ctype]["count"] += 1
                    component_stats[ctype]["total_est_hours"] += est_h
                    component_stats[ctype]["total_actual_hours"] += act_h
                    component_stats[ctype]["total_minutes"] += dur

                    # Operator stats
                    op = getattr(item, "started_by", "") or getattr(item, "assigned_to", "") or ""
                    if op:
                        if op not in operator_stats:
                            operator_stats[op] = {"items_completed": 0, "total_minutes": 0, "components": {}}
                        if getattr(item, "finished_at", ""):
                            operator_stats[op]["items_completed"] += 1
                        operator_stats[op]["total_minutes"] += dur
                        operator_stats[op]["components"][ctype] = operator_stats[op]["components"].get(ctype, 0) + 1

                    # Machine stats
                    mach = getattr(item, "machine", "") or ""
                    if mach:
                        if mach not in machine_stats:
                            machine_stats[mach] = {"items": 0, "total_minutes": 0}
                        machine_stats[mach]["items"] += 1
                        machine_stats[mach]["total_minutes"] += dur

            # Compute averages for components
            for ctype, cs in component_stats.items():
                if cs["count"] > 0:
                    cs["avg_minutes"] = round(cs["total_minutes"] / cs["count"], 1)
                    cs["avg_est_hours"] = round(cs["total_est_hours"] / cs["count"], 2)
                else:
                    cs["avg_minutes"] = 0
                    cs["avg_est_hours"] = 0

            # Compute efficiency for operators
            for op, os_data in operator_stats.items():
                if os_data["total_minutes"] > 0 and os_data["items_completed"] > 0:
                    os_data["avg_minutes_per_item"] = round(os_data["total_minutes"] / os_data["items_completed"], 1)
                else:
                    os_data["avg_minutes_per_item"] = 0

            efficiency_pct = round((total_estimated / total_actual * 100), 1) if total_actual > 0 else 0

            self.set_header("Content-Type", "application/json")
            self.write(json_encode({
                "ok": True,
                "summary": {
                    "total_work_orders": wo_count,
                    "completed_work_orders": completed_count,
                    "total_estimated_hours": round(total_estimated, 2),
                    "total_actual_hours": round(total_actual, 2),
                    "efficiency_pct": efficiency_pct,
                },
                "by_operator": operator_stats,
                "by_machine": machine_stats,
                "by_component_type": component_stats,
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class PurchasedItemsAPIHandler(BaseHandler):
    """GET /api/work-orders/purchased — List purchased items for a job.
       POST /api/work-orders/purchased/pick — Update pick status."""
    required_roles = ["admin", "estimator", "shop"]

    def get(self):
        try:
            job_code = self.get_argument("job_code", "")
            if not job_code:
                self.write(json_encode({"ok": False, "error": "Missing job_code"}))
                return
            from shop_drawings.work_orders import get_purchased_items_for_job
            items = get_purchased_items_for_job(SHOP_DRAWINGS_DIR, job_code)
            total_cost = round(sum(i.get("unit_cost", 0) * i.get("quantity", 0) for i in items), 2)
            picked = sum(1 for i in items if i.get("pick_status") in ("picked", "staged"))
            self.write(json_encode({
                "ok": True,
                "items": items,
                "total_cost": total_cost,
                "total_items": len(items),
                "picked_items": picked,
            }))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            pick_status = body.get("pick_status", "picked").strip()
            picked_by = body.get("picked_by", self.get_current_user() or "shop")

            if not job_code or not item_id:
                self.write(json_encode({"ok": False, "error": "Missing job_code or item_id"}))
                return

            from shop_drawings.work_orders import pick_purchased_item
            result = pick_purchased_item(SHOP_DRAWINGS_DIR, job_code, item_id,
                                          picked_by, pick_status)
            if result.get("ok"):
                self._log("picked_purchased_item", "work_order_item", item_id, {"job_code": job_code, "pick_status": pick_status})
            self.write(json_encode(result))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


class WorkOrderLoadingHandler(BaseHandler):
    """POST /api/work-orders/loading — Update loading/shipping status for an item."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            body = json_decode(self.request.body)
            job_code = body.get("job_code", "").strip()
            item_id = body.get("item_id", "").strip()
            new_status = body.get("loading_status", "").strip()
            updated_by = body.get("updated_by", self.get_current_user() or "shop")
            truck_number = body.get("truck_number", "").strip()

            if not job_code or not item_id or not new_status:
                self.write(json_encode({"ok": False, "error": "Missing job_code, item_id, or loading_status"}))
                return

            # ── QC HOLD POINT: Check if item requires QC approval before loading ──
            if HAS_SHOP_DRAWINGS:
                wo, item_obj = find_work_order_by_item(SHOP_DRAWINGS_DIR, job_code, item_id)
                if item_obj:
                    hold_check = check_qc_hold_for_loading(item_obj)
                    if hold_check is not None:
                        self.set_header("Content-Type", "application/json")
                        self.write(json_encode(hold_check))
                        return

            result = update_loading_status(SHOP_DRAWINGS_DIR, job_code, item_id,
                                            new_status, updated_by, truck_number)

            # Auto-advance project stage based on loading status
            if result.get("ok"):
                if new_status == "shipped":
                    _auto_advance_stage(job_code, "shipping")
                elif new_status == "delivered":
                    _auto_advance_stage(job_code, "install")

            self.set_header("Content-Type", "application/json")
            self.write(json_encode(result))
        except Exception as e:
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


