class FinancialProjectsAPIHandler(BaseHandler):
    """GET /api/financial/projects — Return all projects with financial data."""
    def get(self):
        self.set_header("Content-Type", "application/json")
        try:
            projects = []
            os.makedirs(PROJECTS_DIR, exist_ok=True)
            for d in sorted(os.listdir(PROJECTS_DIR), reverse=True):
                dpath = os.path.join(PROJECTS_DIR, d)
                if not os.path.isdir(dpath):
                    continue
                meta_path = os.path.join(dpath, "metadata.json")
                proj = {"job_code": d, "project_name": d, "customer": "", "stage": "quote",
                        "material_cost": None, "sell_price": None, "margin": None}
                if os.path.isfile(meta_path):
                    try:
                        with open(meta_path) as f:
                            meta = json.load(f)
                        proj["project_name"] = meta.get("project_name", d)
                        cust = meta.get("customer", {})
                        proj["customer"] = cust.get("name", "") if isinstance(cust, dict) else str(cust)
                        proj["stage"] = meta.get("stage", "quote")
                        proj["created_at"] = meta.get("created_at", "")
                        proj["updated_at"] = meta.get("updated_at", "")
                    except Exception:
                        pass
                ver_files = sorted(glob.glob(os.path.join(dpath, "versions", "v*.json")), reverse=True)
                if not ver_files:
                    ver_files = sorted(glob.glob(os.path.join(dpath, "v*.json")), reverse=True)
                if ver_files:
                    try:
                        with open(ver_files[0]) as vf:
                            vdata = json.load(vf)
                        bom = vdata.get("bom_result", vdata.get("bom", {}))
                        if isinstance(bom, dict):
                            cost = bom.get("material_cost", bom.get("total_material_cost", None))
                            sell = bom.get("sell_price", bom.get("total_price", bom.get("grand_total", None)))
                            if cost and isinstance(cost, (int, float)):
                                proj["material_cost"] = round(float(cost), 2)
                            if sell and isinstance(sell, (int, float)):
                                proj["sell_price"] = round(float(sell), 2)
                            if proj["material_cost"] and proj["sell_price"] and proj["sell_price"] > 0:
                                proj["margin"] = round((proj["sell_price"] - proj["material_cost"]) / proj["sell_price"] * 100, 1)
                    except Exception:
                        pass
                projects.append(proj)
            self.write(json_encode({"projects": projects}))
        except Exception as e:
            logger.error(f"FinancialProjectsAPIHandler error: {e}", exc_info=True)
            self.write({"projects": []})

class SalesLeadsAPIHandler(BaseHandler):
    """GET/POST/PUT /api/sales/leads — Full sales leads CRUD with persistent storage."""
    def get(self):
        self.set_header("Content-Type", "application/json")
        try:
            leads_path = os.path.join(DATA_DIR, "sales_leads.json")
            leads = []
            if os.path.isfile(leads_path):
                with open(leads_path) as f:
                    leads = json.load(f)
            self.write(json_encode({"leads": leads}))
        except Exception as e:
            logger.error(f"SalesLeadsAPIHandler GET error: {e}", exc_info=True)
            self.write({"leads": []})

    def post(self):
        self.set_header("Content-Type", "application/json")
        try:
            body = json_decode(self.request.body)
            leads_path = os.path.join(DATA_DIR, "sales_leads.json")
            leads = []
            if os.path.isfile(leads_path):
                with open(leads_path) as f:
                    leads = json.load(f)
            yr = datetime.datetime.now().strftime("%Y")
            mx = 0
            for ld in leads:
                lid = ld.get("id", "")
                if lid.startswith(f"LEAD-{yr}-"):
                    try: mx = max(mx, int(lid.split("-")[-1]))
                    except Exception: pass
            lead_id = f"LEAD-{yr}-{mx+1:04d}"
            body["id"] = lead_id
            body["status"] = body.get("status", "new")
            body["created_at"] = datetime.datetime.now().isoformat()
            body["updated_at"] = body["created_at"]
            body["stage_changed_at"] = body["created_at"]
            leads.append(body)
            with open(leads_path, "w") as f:
                json.dump(leads, f, indent=2)
            self.write({"status": "ok", "id": lead_id})
        except Exception as e:
            logger.error(f"SalesLeadsAPIHandler POST error: {e}", exc_info=True)
            self.write({"status": "error", "message": str(e)})

    def put(self):
        """Update lead status, fields, or convert to customer."""
        self.set_header("Content-Type", "application/json")
        try:
            body = json_decode(self.request.body)
            lead_id = body.get("id")
            if not lead_id:
                self.write({"status": "error", "message": "Missing id"}); return
            leads_path = os.path.join(DATA_DIR, "sales_leads.json")
            leads = []
            if os.path.isfile(leads_path):
                with open(leads_path) as f: leads = json.load(f)
            for ld in leads:
                if ld.get("id") == lead_id:
                    old_status = ld.get("status", "")
                    for k in ["status","company","contact_name","phone","email","source",
                              "estimated_value","follow_up_date","assigned_to","notes",
                              "converted","converted_customer_id","lost_reason"]:
                        if k in body: ld[k] = body[k]
                    if body.get("status") and body["status"] != old_status:
                        ld["stage_changed_at"] = datetime.datetime.now().isoformat()
                    ld["updated_at"] = datetime.datetime.now().isoformat()
                    with open(leads_path, "w") as f: json.dump(leads, f, indent=2)
                    self.write({"status": "ok"}); return
            self.write({"status": "error", "message": "Not found"})
        except Exception as e:
            logger.error(f"SalesLeadsAPIHandler PUT error: {e}", exc_info=True)
            self.write({"status": "error", "message": str(e)})

