            doc.build(story)
            pdf_bytes = buf.getvalue()

            fname = f"Customer_Report_{cid or 'All'}_{now.strftime('%Y%m%d')}.pdf"
            self.set_header("Content-Type", "application/pdf")
            self.set_header("Content-Disposition", f'attachment; filename="{fname}"')
