class WorkStationScanHandler(BaseHandler):
    """POST /api/work-station/scan — Scan QR at work station."""
    required_roles = ["admin", "estimator", "shop"]

    def post(self):
        try:
            self.set_header("Content-Type", "application/json")
            body = json_decode(self.request.body)
            qr_code = body.get("qr_code", "").strip()
            station = body.get("station", "").strip()
            if not qr_code:
                self.set_status(400)
                self.write(json_encode({"ok": False, "error": "qr_code required"}))
                return
            item = {}
            try:
                from shop_drawings.work_orders import scan_qr_code
                result = scan_qr_code(SHOP_DRAWINGS_DIR, qr_code, station)
                if result:
                    item = result
            except Exception:
                pass
            self.write(json_encode({"ok": True, "status": "ok", "item": item, "station": station}))
        except Exception as e:
            logger.error(f"WorkStationScanHandler error: {e}", exc_info=True)
            self.set_status(500)
            self.write(json_encode({"ok": False, "error": str(e)}))


